import type { ExerciseDef, EquipOption, Muscle, TrainingType } from './types';

// weekly, per-muscle set targets at "progressive overload" baseline (moderate effort, ~1-3 reps
// in reserve most sets) — roughly the commonly-cited MEV-to-MAV hypertrophy volume zone per
// muscle per week (e.g. Renaissance Periodization volume landmarks, Schoenfeld volume meta-analyses).
// Forearms sits low deliberately: they already get heavy indirect work from every gripping pull
// (which counts nothing toward the bar, since muscleVolumes() credits primary muscle only), so
// the direct-work target is a top-up, not a full hypertrophy allotment. 7 rather than a rounder
// 6 or 8 because of set-count rounding at the HIT multiplier (0.4): 6×0.4 = 2.4 target sets has
// no integer inside the wizard balancer's 85-115% band, so every HIT program either under- or
// overshot; 7×0.4 = 2.8 rounds cleanly to 3.
export const MUSCLE_TARGETS: Record<Muscle, number> = {
  'Back': 16, 'Biceps': 10, 'Rear Delts': 8, 'Chest': 12, 'Triceps': 8, 'Forearms': 7, 'Shoulders': 10,
  'Quads': 14, 'Hamstrings': 10, 'Glutes': 10, 'Calves': 12, 'Core': 10
};

// multiplier applied to the baseline above per training style:
//  - Strength (low reps near 1RM, not to failure): load does the work, less volume needed.
//  - High Intensity/Failure (Mentzer/HIT-style, every set to true failure): far less volume needed,
//    and recovery cost is much higher, so weekly tolerance drops a lot.
//  - Endurance (higher reps, submaximal, rarely to failure): needs more total sets to add up.
//  - General/maintenance: well under MAV is enough to hold on to gains without progressing hard.
export const TRAINING_MULT: Record<TrainingType, number> = {
  progressive_overload: 1, strength: 0.6, hit: 0.4, endurance: 1.3, general: 0.6
};

export const TRAINING_LABELS: Record<TrainingType, string> = {
  progressive_overload: 'Progressive Overload', strength: 'Strength', hit: 'High Intensity (Failure)',
  endurance: 'Endurance', general: 'General Fitness'
};

export const TRAINING_TYPE_DESCS: Record<TrainingType, string> = {
  progressive_overload: 'Steadily add weight or reps most sessions, 1-3 reps shy of failure. Standard weekly volume per muscle.',
  strength: 'Low reps near your max, not to failure (e.g. 5/3/1-style). Load does the work — needs less weekly volume.',
  hit: 'Every set taken to true failure (Mentzer/HIT-style). Each set is so taxing you need far less weekly volume and more recovery time.',
  endurance: 'Higher reps, lighter loads, rarely to failure. Needs more total weekly volume to add up to a stimulus.',
  general: 'Balanced, moderate effort for maintenance. Well under max volume is enough to hold onto gains.'
};

// default rep count used when an exercise is newly added to a program — pulled toward the
// active training plan's typical rep style rather than always defaulting to the top of range.
export function planRepDefault(trainingType: TrainingType, lib: ExerciseDef): number {
  const mid = Math.round((lib.repLo + lib.repHi) / 2);
  switch (trainingType) {
    case 'strength': return lib.repLo;
    case 'hit': return Math.max(lib.repLo, mid - 1);
    case 'endurance': return lib.repHi + 3;
    case 'general': return mid;
    default: return lib.repHi; // progressive_overload
  }
}

type RawExLib = Record<string, Omit<ExerciseDef, 'secondary'>>;

// restBase (seconds) reflects load + joints/muscles involved + systemic fatigue cost:
// heavy multi-joint barbell lifts rest longest, moderate compound machine/cable work less,
// small single-joint isolation work needs the least recovery between sets.
const RAW_EXLIB: RawExLib = {
  deadlift: { name: 'Barbell Deadlift', muscle: 'Back', compound: true, restBase: 180, pattern: 'hinge', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'smith', label: 'Smith Machine' }, { v: 'trapbar', label: 'Trap Bar' }], repLo: 6, repHi: 8, cue: 'Set up with the barbell over your mid-foot, feet hip-width apart, and grip the bar just outside your knees. Hinge at the hips and bend your knees until your shins touch the bar, keeping your chest up and your back flat. Take a deep breath, brace your core, and drive through the floor by pushing your feet down while keeping the bar dragging close along your shins and thighs as you stand tall. Lock out by squeezing your glutes at the top rather than hyperextending your lower back. Avoid rounding your lower back or letting the bar drift away from your body, both of which shift stress onto your spine.', videoId: 'NVpwlMFrB3I' },
  lat_pulldown: { name: 'Lat Pulldown', muscle: 'Back', compound: true, restBase: 90, pattern: 'pulldown', equip: [{ v: 'machine', label: 'Machine' }, { v: 'cable', label: 'Cable' }], repLo: 10, repHi: 12, cue: 'Sit at the machine with your thighs secured under the pad and grip the bar slightly wider than shoulder width. Lean back slightly, brace your core, and pull the bar down toward your upper chest by driving your elbows down and back rather than pulling with your arms. Squeeze your shoulder blades together at the bottom of the movement before slowly returning the bar to full arm extension under control. Avoid using momentum by swinging your torso or yanking the bar behind your neck, as this reduces lat engagement and stresses the shoulders.', videoId: 'SALxEARiMkw' },
  seated_row: { name: 'Seated Cable Row', muscle: 'Back', compound: true, restBase: 90, pattern: 'row', equip: [{ v: 'cable', label: 'Cable' }, { v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Sit at the cable row station with your knees slightly bent and feet braced on the platform, then grab the handle with your arms fully extended and your torso upright. Pull the handle toward your lower abdomen by driving your elbows straight back and squeezing your shoulder blades together, keeping your torso relatively still throughout. Pause briefly at full contraction, then extend your arms slowly to return to the stretched position without letting your shoulders round forward. Avoid leaning far back and using your body weight to heave the weight, which turns the row into a momentum-driven swing instead of a controlled back exercise.', videoId: 'OeLb503NZHk' },
  barbell_row: { name: 'Barbell Row', muscle: 'Back', compound: true, restBase: 100, pattern: 'row', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 8, repHi: 10, cue: 'Stand with feet hip-width apart, grip the barbell just outside your knees, and hinge forward from the hips until your torso is roughly 45 degrees to the floor with a flat back. Pull the bar up toward your lower ribcage by driving your elbows back and up, keeping the bar close to your body throughout the pull. Squeeze your shoulder blades together at the top, then lower the bar under control back to a full stretch. Keep your core braced and avoid jerking the weight up with your lower back or standing more upright mid-set, both of which turn the row into a cheat movement.', videoId: 'rqTOAM8WoeM' },
  dumbbell_row: { name: 'Dumbbell Row', muscle: 'Back', compound: true, restBase: 90, pattern: 'row', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Place one knee and hand on a bench for support, keeping your back flat and roughly parallel to the floor, with the dumbbell hanging directly under your shoulder. Pull the dumbbell up toward your hip by driving your elbow up and back, keeping it close to your body rather than flaring it out. Squeeze your shoulder blade at the top of the movement, then lower the dumbbell under control to a full stretch. Avoid rotating your torso to help heave the weight up, which shifts work away from the back and onto momentum.', videoId: 'roCP6wCXPqo' },
  barbell_curl: { name: 'Barbell Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }, { v: 'ezbar', label: 'EZ-Bar' }], repLo: 10, repHi: 12, cue: 'Stand tall with feet shoulder-width apart, holding the barbell with an underhand, shoulder-width grip and your arms fully extended in front of your thighs. Curl the bar upward by flexing your elbows while keeping your upper arms pinned to your sides and your torso still. Squeeze your biceps hard at the top, then lower the bar slowly and under control back to full extension. Avoid swinging your hips or leaning back to sling the weight up, since this cheats the biceps out of the work and can strain your lower back.', videoId: 'JJB8XgKltA8' },
  face_pull: { name: 'Face Pull', muscle: 'Rear Delts', compound: false, restBase: 60, pattern: 'face_pull', equip: [{ v: 'cable', label: 'Cable' }, { v: 'band', label: 'Band' }], repLo: 12, repHi: 15, cue: 'Set a cable pulley to roughly eye or upper-chest height, attach a rope handle, and step back to create tension with your arms extended in front of you. Pull the rope toward your face by driving your elbows out and back, aiming to finish with your hands near your ears and your knuckles facing behind you. Focus on externally rotating your shoulders and squeezing your rear delts and upper back at the end range before returning slowly to the start. Avoid using a heavy weight that forces you to pull with your arms and lean back, which turns the movement into a row instead of targeting the rear delts and rotator cuff.', videoId: 'eTCBSFlCJ_s' },
  bench_press: { name: 'Bench Press', muscle: 'Chest', compound: true, restBase: 120, pattern: 'bench_press', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }, { v: 'smith', label: 'Smith Machine' }], repLo: 6, repHi: 8, cue: 'Lie on the bench with your eyes roughly under the bar, feet flat on the floor, and shoulder blades pulled back and down into the bench. Grip the bar slightly wider than shoulder width, unrack it, and lower it under control to touch your mid-chest while keeping your elbows at about a 45-degree angle to your torso. Drive the bar back up in a slight arc toward your face, pressing your feet into the floor for stability, until your arms are fully locked out. Avoid flaring your elbows straight out to the sides or bouncing the bar off your chest, both of which increase shoulder strain and reduce control.', videoId: 'gRVjAtPip0Y' },
  overhead_press: { name: 'Overhead Press', muscle: 'Shoulders', compound: true, restBase: 105, pattern: 'overhead_press', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }, { v: 'smith', label: 'Smith Machine' }], repLo: 8, repHi: 10, cue: 'Stand with feet shoulder-width apart, holding the barbell at shoulder height with your hands just outside shoulder width and elbows slightly in front of the bar. Brace your core and glutes, then press the bar straight overhead, moving your head back slightly to let the bar travel in a vertical line, and push your head through at the top to finish with the bar over your ears. Lower the bar back to shoulder height under control while keeping your ribcage down and avoiding an excessive backward lean. Avoid arching your lower back excessively to press the weight up, since this substitutes spinal extension for genuine shoulder strength and can lead to back strain.', videoId: 'F3QY5vMz_6I' },
  incline_db_press: { name: 'Incline DB Press', muscle: 'Chest', compound: true, restBase: 100, pattern: 'incline_press', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'smith', label: 'Smith Machine' }], repLo: 10, repHi: 12, cue: 'Set an adjustable bench to a 30-45 degree incline and sit with a dumbbell in each hand resting on your thighs, then kick them up to shoulder height as you lie back. Press the dumbbells up and slightly inward until your arms are extended above your upper chest, keeping your wrists stacked over your elbows. Lower the dumbbells slowly to the sides of your upper chest, allowing your elbows to travel to about 45 degrees from your torso, then press back up. Avoid setting the bench too steep, which shifts emphasis away from the chest and onto the front deltoids.', videoId: 'gl8H4QLXKTo' },
  triceps_pushdown: { name: 'Triceps Pushdown', muscle: 'Triceps', compound: false, restBase: 60, pattern: 'triceps_extension', equip: [{ v: 'cable', label: 'Cable' }, { v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Attach a straight bar or rope to a high cable pulley and grip it with your elbows tucked at your sides and bent to about 90 degrees. Keeping your upper arms pinned against your torso, extend your elbows to push the attachment down until your arms are fully straight. Pause and squeeze your triceps at the bottom, then let the weight rise under control back to the starting position without letting your elbows drift forward or backward. Avoid leaning your whole body into the movement or letting your elbows flare away from your sides, which shifts effort off the triceps.', videoId: 'ozwo9RGm7QU' },
  lateral_raise: { name: 'Lateral Raise', muscle: 'Shoulders', compound: false, restBase: 60, pattern: 'lateral_raise', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'cable', label: 'Cable' }, { v: 'machine', label: 'Machine' }], repLo: 12, repHi: 15, cue: 'Stand holding a dumbbell in each hand at your sides with a slight bend in your elbows and your torso upright. Raise both arms out to the sides, leading with your elbows, until they reach roughly shoulder height, keeping your wrists neutral or slightly tilted so your pinkies lead. Pause briefly at the top, then lower the dumbbells slowly back to your sides under control. Avoid using momentum by shrugging your traps or swinging the weights up, since heavier weight lifted with body english trains your traps far more than your side delts.', videoId: 'Y29xKcze8Ik' },
  back_squat: { name: 'Back Squat', muscle: 'Quads', compound: true, restBase: 150, pattern: 'squat', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'smith', label: 'Smith Machine' }], repLo: 6, repHi: 8, cue: 'Set the barbell on your upper traps, unrack it, and step back into a stance about shoulder-width apart with your toes turned slightly outward. Take a deep breath, brace your core, and lower yourself by pushing your hips back and bending your knees, keeping your chest up and your weight balanced over your mid-foot until your hip crease drops at least to knee level. Drive through your whole foot to stand back up, keeping your knees tracking in line with your toes throughout the ascent. Avoid letting your knees cave inward or your heels rise off the floor, both of which signal a loss of stability and increase injury risk.', videoId: 'irA7MTz96ho' },
  leg_curl: { name: 'Leg Curl', muscle: 'Hamstrings', compound: false, restBase: 75, pattern: 'leg_curl', equip: [{ v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Lie face down on the leg curl machine with the padded lever resting just above your heels and your knees aligned with the machine\'s pivot point. Curl your heels toward your glutes by contracting your hamstrings, keeping your hips pressed into the pad throughout the movement. Pause briefly at full contraction, then lower the weight slowly back to the starting position without letting it slam down. Avoid raising your hips off the pad to generate momentum, as this reduces hamstring tension and can strain your lower back.', videoId: '3gZm9wGTsEo' },
  pullup: { name: 'Pull-Up', muscle: 'Back', compound: true, restBase: 100, pattern: 'pullup', equip: [{ v: 'bodyweight', label: 'Bodyweight' }, { v: 'assisted', label: 'Assisted Machine' }], repLo: 8, repHi: 10, cue: 'Grip a pull-up bar slightly wider than shoulder width with your palms facing away from you and hang with your arms fully extended and your core braced. Pull yourself up by driving your elbows down toward your hips until your chin clears the bar, focusing on initiating the movement with your lats rather than your arms. Lower yourself back down under control to a full dead hang before starting the next rep. Avoid kipping or swinging your legs to generate momentum, which turns the exercise into a whole-body heave instead of a controlled back and biceps movement.', videoId: '1rRmIzEsl_4' },
  db_shoulder_press: { name: 'DB Shoulder Press', muscle: 'Shoulders', compound: true, restBase: 90, pattern: 'overhead_press', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Sit or stand holding a dumbbell in each hand at shoulder height with your palms facing forward and your core braced. Press the dumbbells straight overhead until your arms are fully extended, allowing the dumbbells to travel slightly inward without letting them clang together at the top. Lower the dumbbells back to shoulder height under control, keeping your elbows at roughly 45 degrees from your torso rather than flared straight out. Avoid arching your lower back excessively to press the weight up, especially when standing, since this shifts load onto your spine instead of your shoulders.', videoId: '1jYq9QQEWqE' },
  cable_fly: { name: 'Cable Fly', muscle: 'Chest', compound: false, restBase: 60, pattern: 'fly', equip: [{ v: 'cable', label: 'Cable' }, { v: 'machine', label: 'Machine' }], repLo: 12, repHi: 15, cue: 'Set two cable pulleys to roughly shoulder height, grab a handle in each hand, and step forward into a slight staggered stance with your arms extended out to your sides and a soft bend in your elbows. Keeping that elbow bend fixed, bring your hands together in a wide arcing motion until they meet in front of your chest, squeezing your pecs at the point of contraction. Slowly reverse the motion, allowing your arms to open back out to the sides under control until you feel a stretch across your chest. Avoid bending your elbows more as you press the handles together, which turns the fly into a press and takes tension off the chest.', videoId: 'ovFc-5YdcXw' },
  hammer_curl: { name: 'Hammer Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Stand holding a dumbbell in each hand at your sides with your palms facing your body in a neutral grip. Curl the dumbbells up by bending your elbows while keeping your upper arms fixed against your torso, maintaining the neutral wrist position throughout the movement. Squeeze your biceps and forearms at the top, then lower the dumbbells slowly back to full extension. Avoid swinging your shoulders or using momentum to heave the weights up, since this reduces tension on the biceps and brachioradialis.', videoId: 'BRVDS6HVR9Q' },
  rdl: { name: 'Romanian Deadlift', muscle: 'Hamstrings', compound: true, restBase: 120, pattern: 'hinge', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }], repLo: 8, repHi: 10, cue: 'Stand holding a barbell or dumbbells in front of your thighs with your feet hip-width apart and a soft bend in your knees that you maintain throughout the set. Push your hips straight back while keeping the weight close to your legs and your spine neutral, lowering it until you feel a strong stretch in your hamstrings, typically around shin or mid-shin height. Keep your shoulders back and chest up as you hinge, then drive your hips forward to return to standing, squeezing your glutes at the top. Avoid rounding your lower back or turning the movement into a squat by bending your knees excessively, since the Romanian deadlift should be driven by hip hinge, not knee flexion.', videoId: '_oyxCn2iSjU' },
  leg_press: { name: 'Leg Press', muscle: 'Quads', compound: true, restBase: 100, pattern: 'leg_press', equip: [{ v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Sit back in the leg press machine with your feet placed shoulder-width apart on the platform, knees tracking in line with your toes. Release the safety catches and lower the platform by bending your knees until they reach about a 90-degree angle, keeping your lower back pressed into the pad. Drive through your heels to press the platform back up without fully locking out your knees at the top. Keep your core braced throughout to prevent your hips from rounding off the seat. Avoid letting your knees cave inward or placing your feet too low on the platform, as this shifts stress onto the knees instead of the quads.', videoId: 'K5n2vg3oZa4' },
  hip_thrust: { name: 'Hip Thrust', muscle: 'Glutes', compound: true, restBase: 90, pattern: 'hip_thrust', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Sit on the ground with your upper back braced against a bench and roll a barbell over your hips, using a pad for comfort. Plant your feet flat on the floor about hip-width apart, then drive through your heels to lift your hips until your body forms a straight line from shoulders to knees. Squeeze your glutes hard at the top and pause briefly before lowering under control. Keep your chin tucked and ribs down throughout to avoid hyperextending your lower back. A common mistake is pushing through the toes or overarching the spine at lockout instead of finishing the movement with the glutes.', videoId: 'pF17m_CXfL0' },
  calf_raise: { name: 'Standing Calf Raise', muscle: 'Calves', compound: false, restBase: 60, pattern: 'calf_raise', equip: [{ v: 'machine', label: 'Machine' }, { v: 'dumbbell', label: 'Dumbbell' }, { v: 'bodyweight', label: 'Bodyweight' }], repLo: 12, repHi: 15, cue: 'Stand on the platform of a calf raise machine or a sturdy step with the balls of your feet on the edge and your heels hanging off. Lower your heels below the platform to feel a deep stretch in your calves, then press through the balls of your feet to rise as high onto your toes as possible. Pause briefly at the top and squeeze your calves before lowering back down under control. Keep your knees nearly straight throughout so the tension stays on the calves rather than shifting to the quads. Avoid bouncing at the bottom of the stretch, which reduces muscle tension and increases strain on the Achilles tendon.', videoId: '97NbelB5yvQ' },
  seated_calf_raise: { name: 'Seated Calf Raise', muscle: 'Calves', compound: false, restBase: 60, pattern: 'calf_raise', equip: [{ v: 'machine', label: 'Machine' }], repLo: 12, repHi: 15, cue: 'Sit at the seated calf raise machine with the balls of your feet on the footplate and the padded lever resting just above your knees. Lower your heels as far as comfortable to stretch the calves, then press the balls of your feet down to raise the pad as high as possible. Focus on squeezing the calves hard at the top of each rep rather than relying on momentum. Keep your torso upright and avoid using your hands to bounce the weight up. Because the seated position bends the knee, this variation emphasizes the soleus more than the gastrocnemius, so use a slow, controlled tempo for the best results.', videoId: 'ORY-ke6vcgk' },

  decline_bench_press: { name: 'Decline Bench Press', muscle: 'Chest', compound: true, restBase: 110, pattern: 'bench_press', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }, { v: 'smith', label: 'Smith Machine' }], repLo: 8, repHi: 10, cue: 'Lie back on a decline bench with your legs secured under the footpads and your feet locked in place. Grip the bar slightly wider than shoulder-width, unrack it, and lower it under control to the lower part of your chest, keeping your elbows at roughly a 45-degree angle from your torso. Press the bar back up in a straight line until your arms are fully extended, without locking out aggressively. Keep your shoulder blades pulled back and down against the bench throughout the set for shoulder stability. Avoid bouncing the bar off your chest or flaring your elbows out to 90 degrees, both of which increase strain on the shoulder joint.', videoId: 'FFyGwcLnDYc' },
  pushup: { name: 'Push-Up', muscle: 'Chest', compound: true, restBase: 60, pattern: 'pushup', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 12, repHi: 20, cue: 'Start in a high plank position with your hands slightly wider than shoulder-width and your body forming a straight line from head to heels. Lower your chest toward the floor by bending your elbows at roughly a 45-degree angle to your torso, keeping your core and glutes braced. Push through your palms to extend your arms and return to the starting position without letting your hips sag or pike upward. Keep your neck neutral by looking at a spot on the floor slightly ahead of you rather than straight down. A common mistake is letting the hips drop or flaring the elbows straight out to the sides, which places unnecessary stress on the shoulders.', videoId: 'WDIpL0pjun0' },
  pec_deck: { name: 'Pec Deck', muscle: 'Chest', compound: false, restBase: 60, pattern: 'fly', equip: [{ v: 'machine', label: 'Machine' }], repLo: 12, repHi: 15, cue: 'Sit in the pec deck machine with your back flat against the pad and adjust the seat so the handles or arm pads are at chest height. Grip the handles or place your forearms against the pads with a slight bend in your elbows, then squeeze your arms together in front of your chest in a hugging motion. Pause briefly at full contraction to maximize the squeeze on your pecs before returning slowly to the stretched position. Keep your shoulders down and back throughout to avoid letting the shoulders round forward. Avoid using momentum to slam the pads together, as this shifts tension away from the chest and onto the front of the shoulders.', videoId: 'wsNAD1BpiaE' },
  dip: { name: 'Dip', muscle: 'Chest', compound: true, restBase: 90, pattern: 'dip', equip: [{ v: 'bodyweight', label: 'Bodyweight' }, { v: 'assisted', label: 'Assisted Machine' }], repLo: 8, repHi: 12, cue: 'Grip the parallel bars with your arms fully extended and your body suspended above them, leaning your torso slightly forward to emphasize the chest. Lower your body by bending your elbows until your upper arms are roughly parallel to the floor, keeping your shoulders down away from your ears. Press through your palms to extend your arms back to the starting position, avoiding a hard lockout that stresses the elbow joints. Keep your core engaged to prevent excessive swinging during the movement. Avoid descending too deep if you feel pinching in the front of the shoulder, as going below parallel can place excessive strain on the shoulder joint.', videoId: 'K5JxupmoLW4' },

  chest_supported_row: { name: 'Chest-Supported Row', muscle: 'Back', compound: true, restBase: 90, pattern: 'row', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Lie chest-down on an inclined support bench with a dumbbell in each hand, letting your arms hang straight down toward the floor. Row the dumbbells up by driving your elbows back and squeezing your shoulder blades together, keeping your elbows close to your body. Pause briefly at the top of the movement before lowering the weights under control back to a full stretch. Keep your chest pressed into the pad throughout to eliminate momentum and isolate the back muscles. Avoid shrugging your shoulders up toward your ears, which shifts the work away from the lats and mid-back and onto the traps.', videoId: '_b6ch2nIchk' },
  tbar_row: { name: 'T-Bar Row', muscle: 'Back', compound: true, restBase: 100, pattern: 'row', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'machine', label: 'Machine' }], repLo: 8, repHi: 10, cue: 'Straddle the T-bar row machine or landmine attachment and hinge forward at the hips until your torso is roughly parallel to the floor, maintaining a neutral spine. Grip the handles with your arms extended, then pull the weight up toward your lower chest by driving your elbows back and squeezing your shoulder blades together. Lower the weight back down under control until your arms are fully extended and you feel a stretch in your lats. Keep your core braced and avoid rounding your lower back throughout the set. A common mistake is using body momentum to heave the weight up rather than pulling with the back muscles.', videoId: 'BbBR3v2UShw' },
  single_arm_row: { name: 'Single-Arm Dumbbell Row', muscle: 'Back', compound: true, restBase: 75, pattern: 'row', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Place one knee and hand on a flat bench for support, keeping your spine flat and parallel to the floor, with your other foot planted on the ground. Hold a dumbbell in your free hand with your arm fully extended, then row the weight up by driving your elbow back and squeezing your shoulder blade toward your spine. Lower the dumbbell back down under control until your arm is fully extended and your shoulder feels a slight stretch. Keep your torso still and avoid rotating your hips or twisting your spine as you pull. Avoid using momentum or yanking the weight up, which reduces engagement of the lats and mid-back muscles.', videoId: 'nMFCMNKnLgQ' },
  straight_arm_pulldown: { name: 'Straight-Arm Pulldown', muscle: 'Back', compound: false, restBase: 60, pattern: 'straight_arm_pulldown', equip: [{ v: 'cable', label: 'Cable' }], repLo: 12, repHi: 15, cue: 'Stand facing a cable machine with the pulley set above head height and a straight or lat bar attached, gripping it with a shoulder-width, thumbless or overhand grip. Hinge slightly forward at the hips and, keeping your arms almost fully extended with only a slight bend at the elbows, pull the bar down in an arc until it reaches your thighs. Squeeze your lats hard at the bottom of the movement before allowing the bar to rise back up under control to the starting position. Keep your elbows locked in a fixed position throughout so the movement comes from the shoulder joint, not the elbows. Avoid bending your elbows more as you pull, which turns the exercise into a pushdown-style movement and takes tension off the lats.', videoId: 'duHQk2PxNos' },
  chinup: { name: 'Chin-Up', muscle: 'Back', compound: true, restBase: 100, pattern: 'pullup', equip: [{ v: 'bodyweight', label: 'Bodyweight' }, { v: 'assisted', label: 'Assisted Machine' }], repLo: 8, repHi: 10, cue: 'Grip a pull-up bar with an underhand, shoulder-width grip and hang with your arms fully extended and your body still. Pull yourself upward by driving your elbows down toward your hips until your chin clears the bar, keeping your core braced to minimize swinging. Lower yourself back down under control until your arms are fully extended again before starting the next rep. Focus on initiating the pull with your back and biceps rather than jerking your body upward. Avoid using momentum or kipping your legs to gain height, as this reduces the strength benefit to your back and biceps.', videoId: 'e1YSApl-QcM' },
  back_extension: { name: 'Back Extension', muscle: 'Hamstrings', compound: true, restBase: 75, pattern: 'back_extension', equip: [{ v: 'bodyweight', label: 'Bodyweight' }, { v: 'machine', label: 'Machine' }], repLo: 12, repHi: 15, cue: 'Position your hips on the pad of a 45-degree or Roman chair back extension bench with your feet secured under the footpads and your body forming a straight line. Cross your arms over your chest or place your hands behind your head, then bend forward at the hips, lowering your torso until you feel a stretch in your hamstrings and lower back. Squeeze your glutes and hamstrings to raise your torso back up until your body is in a straight line, without hyperextending past neutral. Keep your spine neutral throughout rather than rounding at the bottom or arching excessively at the top. Avoid using momentum to jerk your torso upward, which shifts stress onto the lower back instead of the glutes and hamstrings.', videoId: 'gLT-WLH84B4' },
  good_morning: { name: 'Good Morning', muscle: 'Hamstrings', compound: true, restBase: 100, pattern: 'hinge', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 8, repHi: 10, cue: 'Set a barbell across your upper back and traps as if setting up for a squat, standing with your feet shoulder-width apart and knees slightly bent. Keeping your spine neutral and core braced, hinge forward at the hips by pushing your glutes back until your torso is roughly parallel to the floor. Feel a stretch through your hamstrings, then drive your hips forward and squeeze your glutes to return to standing. Keep the bar path close to your body and avoid rounding your lower back at any point in the movement. Start with light weight, since rounding the spine or hinging too aggressively at the knees instead of the hips is a common and risky mistake.', videoId: 'f23vXjoG2e8' },

  arnold_press: { name: 'Arnold Press', muscle: 'Shoulders', compound: true, restBase: 90, pattern: 'overhead_press', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 8, repHi: 10, cue: 'Sit on a bench with back support, holding a dumbbell in each hand at shoulder height with your palms facing your body and elbows bent. Press the dumbbells overhead while simultaneously rotating your wrists so your palms face forward at the top of the movement. Reverse the rotation as you lower the dumbbells back to the starting position in front of your shoulders, palms facing you again. Keep your core braced and avoid arching your lower back excessively as you press overhead. Avoid rushing the rotation, since the rotating path is what distinguishes this exercise and targets all three heads of the deltoid.', videoId: '6Z15_WdXmVw' },
  machine_shoulder_press: { name: 'Machine Shoulder Press', muscle: 'Shoulders', compound: true, restBase: 90, pattern: 'overhead_press', equip: [{ v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Adjust the seat height so the handles align with your shoulders when seated, then grip the handles with your palms facing forward or in a neutral grip depending on the machine. Press the handles straight overhead until your arms are fully extended without locking out your elbows aggressively. Lower the handles back down under control until your elbows are just below shoulder height. Keep your back flat against the pad and your core braced to prevent arching your lower back during the press. Avoid flaring your elbows too far back at the bottom of the movement, as this can place unnecessary stress on the shoulder joint.', videoId: 'TnhIyp4kmO8' },
  front_raise: { name: 'Front Raise', muscle: 'Shoulders', compound: false, restBase: 60, pattern: 'front_raise', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'cable', label: 'Cable' }], repLo: 12, repHi: 15, cue: 'Stand with feet shoulder-width apart, holding a dumbbell in each hand in front of your thighs with a slight bend in your elbows. Keeping your core braced and avoiding momentum, raise one or both dumbbells forward and up until they reach approximately shoulder height. Pause briefly at the top before lowering the weights back down under control to the starting position. Keep your torso still throughout, resisting the urge to lean back or swing the weights up. Avoid using excessively heavy weight, which causes swinging and shifts the work away from the front deltoids and onto the lower back.', videoId: 'CH9JzDStL3U' },
  upright_row: { name: 'Upright Row', muscle: 'Shoulders', compound: false, restBase: 60, pattern: 'upright_row', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'cable', label: 'Cable' }], repLo: 10, repHi: 12, cue: 'Stand with feet shoulder-width apart, holding a barbell or dumbbells in front of your thighs with an overhand grip slightly narrower than shoulder-width. Pull the weight straight up along your body by leading with your elbows, raising it to roughly chest or collarbone height. Pause briefly at the top, keeping the weight close to your torso, before lowering it back down under control. Keep your wrists relaxed and avoid shrugging your shoulders up toward your ears during the pull. Use a moderate grip width and stop before your elbows rise above shoulder height, since a narrow grip combined with pulling too high can irritate the shoulder joint.', videoId: 'K0dYqPCaO14' },
  rear_delt_fly: { name: 'Rear Delt Fly', muscle: 'Rear Delts', compound: false, restBase: 60, pattern: 'rear_delt_fly', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'machine', label: 'Machine' }, { v: 'cable', label: 'Cable' }], repLo: 12, repHi: 15, cue: 'Hold a pair of light-to-moderate dumbbells and hinge forward at the hips until your torso is close to parallel with the floor, letting your arms hang straight down with a slight bend in the elbows. Keeping your chest up and spine neutral, sweep the dumbbells out and up in a wide arc until your arms are roughly in line with your shoulders, squeezing your shoulder blades together at the top. Lead with your elbows rather than your hands, and lower the weights back down under control through the same path. Avoid using momentum or turning the movement into a row by bending your elbows too much - the tension should stay on your rear delts, not your upper back.', videoId: '0GSu6Z-Oj7U' },

  incline_curl: { name: 'Incline Dumbbell Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Set an adjustable bench to roughly a 45-60 degree incline and sit back with your shoulders pinned against the pad, letting a dumbbell hang straight down in each hand with palms facing forward. Without letting your elbows drift forward or your shoulders round off the bench, curl the weights up toward your shoulders, squeezing the biceps hard at the top. Keep your upper arm stationary throughout the movement - the shoulder joint shouldn\'t move, only the elbow. Lower the dumbbells slowly back to a full stretch, since that extra stretch at the bottom is what makes this variation so effective for the long head of the biceps; a common mistake is flaring the elbows out or swinging the torso to cheat the weight up.', videoId: '1gCfaEWk_Ds' },
  cable_curl: { name: 'Cable Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'cable', label: 'Cable' }], repLo: 10, repHi: 12, cue: 'Attach a straight or EZ bar to a low pulley and stand facing the machine with feet shoulder-width apart, elbows tucked at your sides and arms extended. Curl the bar up toward your chest by flexing at the elbow only, keeping your upper arms glued to your torso and your wrists neutral. Squeeze your biceps at the top for a beat before lowering the bar under control back to full extension, keeping constant tension on the muscle rather than letting the weight stack rest. Avoid leaning back or using your shoulders to heave the bar up, since the cable\'s constant resistance is meant to keep the biceps working through the entire range of motion.', videoId: '16aEi1a68E0' },
  preacher_curl: { name: 'Preacher Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }, { v: 'ezbar', label: 'EZ-Bar' }], repLo: 10, repHi: 12, cue: 'Sit at the preacher bench with your upper arms flat against the angled pad and your armpits snug against the top edge, holding a barbell, EZ bar, or dumbbells with your arms extended but not fully locked out. Curl the weight up by flexing your elbows while keeping your upper arms pinned to the pad, then squeeze your biceps hard at the top of the movement. Lower the weight slowly and with control, allowing a full stretch at the bottom without letting your elbows hyperextend or the weight drop suddenly. A common mistake is bouncing out of the bottom stretch or lifting your upper arms off the pad to generate momentum, which shifts stress onto the elbows and shoulders instead of the biceps.', videoId: 'R-8Sa0_qiws' },

  overhead_triceps_ext: { name: 'Overhead Triceps Extension', muscle: 'Triceps', compound: false, restBase: 60, pattern: 'triceps_extension', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'cable', label: 'Cable' }, { v: 'ezbar', label: 'EZ-Bar' }], repLo: 10, repHi: 12, cue: 'Stand or sit holding a single dumbbell with both hands cupped under the top plate, and press it overhead until your arms are fully extended. Keeping your upper arms close to your ears and elbows pointed forward, lower the weight behind your head by bending only at the elbows until you feel a deep stretch in your triceps. Drive through the elbows to press the weight back to full extension, focusing on squeezing the triceps rather than using your shoulders. Keep your elbows tucked in throughout - letting them flare outward turns the movement into more of a shoulder exercise and reduces triceps activation.', videoId: 'W6h3t9mkRrY' },
  skull_crusher: { name: 'Skull Crusher', muscle: 'Triceps', compound: false, restBase: 60, pattern: 'triceps_extension', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'ezbar', label: 'EZ-Bar' }, { v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Lie flat on a bench holding an EZ bar or barbell with a shoulder-width overhand grip, arms extended straight up over your chest. Keeping your upper arms vertical and stationary, bend at the elbows to lower the bar down toward your forehead or just behind your head, letting your elbows travel back slightly. Pause briefly at the bottom, then extend your elbows to press the bar back to the starting position, focusing on squeezing the triceps through lockout. Avoid letting your elbows flare outward or drift forward toward your face, as this shifts the load off the triceps and increases strain on the elbow joints.', videoId: 'ShR_FM3-wm4' },
  close_grip_bench: { name: 'Close-Grip Bench Press', muscle: 'Triceps', compound: true, restBase: 100, pattern: 'close_grip_bench', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'smith', label: 'Smith Machine' }], repLo: 8, repHi: 10, cue: 'Lie on a flat bench and grip the barbell with your hands just inside shoulder width, unrack the bar and hold it directly over your chest with arms extended. Lower the bar under control to your lower chest or upper abdomen, keeping your elbows tucked close to your torso rather than flared out. Press the bar back up by driving through your palms and locking out your elbows, focusing on squeezing your triceps at the top. Keep your wrists stacked over your elbows throughout - a grip that\'s too narrow or wrists that bend backward can place unnecessary strain on the wrists and shoulders.', videoId: 'a2G3IdaTcPU' },

  front_squat: { name: 'Front Squat', muscle: 'Quads', compound: true, restBase: 150, pattern: 'squat', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'smith', label: 'Smith Machine' }], repLo: 6, repHi: 8, cue: 'Rack a barbell across the front of your shoulders, either in a clean grip with elbows high or a cross-arm grip, keeping your elbows lifted so the bar doesn\'t roll forward. Stand with feet shoulder-width apart, brace your core, and squat down by bending at the hips and knees simultaneously, keeping your torso upright and your knees tracking over your toes. Descend until your hip crease is at or below knee level, then drive through your midfoot to stand back up, maintaining a high elbow position throughout. Letting your elbows drop is the most common mistake - it causes the bar to roll off your shoulders and your torso to collapse forward.', videoId: 'npVgCT7NznU' },
  hack_squat: { name: 'Hack Squat', muscle: 'Quads', compound: true, restBase: 120, pattern: 'squat', equip: [{ v: 'machine', label: 'Machine' }], repLo: 8, repHi: 10, cue: 'Load the hack squat machine, position your shoulders and back firmly against the pads, and place your feet shoulder-width apart on the platform, slightly ahead of your hips. Release the safety handles and lower yourself by bending your knees and hips, keeping your lower back pressed against the pad, until your thighs are at least parallel to the platform. Drive through your heels and midfoot to press back up to the starting position without locking your knees out aggressively. Avoid letting your knees cave inward or your heels lift off the platform, as this shifts stress away from the quads and onto the knee joints.', videoId: '-lAnEGH2blE' },
  bulgarian_split_squat: { name: 'Bulgarian Split Squat', muscle: 'Quads', compound: true, restBase: 100, pattern: 'split_squat', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'barbell', label: 'Barbell' }], repLo: 10, repHi: 12, cue: 'Stand a couple of feet in front of a bench and rest the top of your rear foot on it, laces down, with your front foot planted far enough forward that your knee won\'t shoot past your toes at the bottom. Keeping your torso upright, lower your back knee straight down toward the floor by bending your front knee and hip, until your front thigh is roughly parallel to the ground. Drive through your front heel to push back up to the starting position, keeping most of your weight on the front leg throughout. A common mistake is placing the front foot too close to the bench, which forces the knee too far forward and makes the movement quad-dominant and unstable rather than glute-focused.', videoId: 'VPhhE6bBzZE' },
  walking_lunge: { name: 'Walking Lunge', muscle: 'Quads', compound: true, restBase: 90, pattern: 'lunge', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'barbell', label: 'Barbell' }, { v: 'bodyweight', label: 'Bodyweight' }], repLo: 10, repHi: 12, cue: 'Stand tall holding dumbbells at your sides or a barbell across your back, and take a long step forward with one leg, lowering your body until both knees are bent to roughly 90 degrees and your back knee hovers just above the floor. Push through your front heel to drive back up to standing, then bring your trailing leg forward into the next step rather than stepping back, continuing to alternate legs as you walk forward. Keep your torso upright and core braced throughout, avoiding letting your front knee cave inward or travel far past your toes. A common mistake is taking too short a stride, which shifts stress onto the front knee instead of the glutes and hamstrings.', videoId: 'BenhAbJiTsw' },
  leg_extension: { name: 'Leg Extension', muscle: 'Quads', compound: false, restBase: 75, pattern: 'leg_extension', equip: [{ v: 'machine', label: 'Machine' }], repLo: 12, repHi: 15, cue: 'Sit on the leg extension machine with your back flat against the pad and the ankle pad resting just above your feet, adjusting the seat so your knees line up with the machine\'s pivot point. Extend your legs by straightening your knees until they\'re fully extended, squeezing your quads hard at the top of the movement. Lower the weight back down slowly and under control rather than letting it drop, stopping just before the weight stack touches down to keep tension on the muscle. Avoid using momentum or jerking the weight up, and don\'t let your hips rise off the seat, since both reduce quad isolation and add strain to the knees.', videoId: 'gI0cn4DMFFI' },

  seated_leg_curl: { name: 'Seated Leg Curl', muscle: 'Hamstrings', compound: false, restBase: 75, pattern: 'leg_curl', equip: [{ v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Sit on the leg curl machine with your back against the pad and position the ankle pad against the back of your lower legs, just above your heels, adjusting the machine so your knees align with the pivot point. Curl your legs by bending your knees and pulling the pad down and back toward the seat, squeezing your hamstrings hard at the bottom of the movement. Return to the starting position slowly, resisting the weight the entire way rather than letting it snap back. Keep your hips and thighs pressed against the pad throughout, since lifting your hips off the seat lets other muscles take over from the hamstrings.', videoId: '_2Kd0d-JEUM' },

  glute_bridge: { name: 'Glute Bridge', muscle: 'Glutes', compound: true, restBase: 75, pattern: 'hip_thrust', equip: [{ v: 'bodyweight', label: 'Bodyweight' }, { v: 'barbell', label: 'Barbell' }], repLo: 12, repHi: 15, cue: 'Lie on your back with your knees bent, feet flat on the floor about hip-width apart, and heels close enough to your glutes that you can just brush them with your fingertips. Drive through your heels to lift your hips up toward the ceiling, squeezing your glutes hard at the top until your body forms a straight line from shoulders to knees. Pause briefly at the top before lowering your hips back down under control, without letting them fully rest on the floor between reps if you want to keep continuous tension. Avoid overarching your lower back to gain height - the lift should come from glute contraction, not lumbar extension.', videoId: 'wPM8icPu6H8' },
  cable_kickback: { name: 'Cable Kickback', muscle: 'Glutes', compound: false, restBase: 60, pattern: 'glute_kickback', equip: [{ v: 'cable', label: 'Cable' }], repLo: 12, repHi: 15, cue: 'Attach an ankle strap to a low cable pulley and secure it around one ankle, then face the machine and hold onto it for balance with a slight forward hinge at the hips. Keeping your leg mostly straight with a soft bend in the knee, kick your leg back and up by squeezing your glute, stopping once your hip is fully extended without over-arching your lower back. Pause and squeeze at the top before returning your leg to the starting position under control, resisting the cable the entire way back. Avoid using your lower back to generate the movement by swinging or hyperextending your spine - the motion should come purely from hip extension.', videoId: 'bVrmtCI00Ys' },
  hip_abduction: { name: 'Hip Abduction Machine', muscle: 'Glutes', compound: false, restBase: 60, pattern: 'hip_abduction', equip: [{ v: 'machine', label: 'Machine' }], repLo: 12, repHi: 15, cue: 'Sit in the hip abduction machine with your back flat against the pad and place the outside of your knees or thighs against the leg pads, adjusting the range so you start with your knees together. Press your legs outward against the resistance by squeezing your outer hips and glutes, moving through a controlled range of motion until your legs are comfortably spread. Pause briefly at the widest point, then let your legs return slowly back to the starting position without letting the weight stack slam down. Avoid leaning your torso forward or using momentum to jerk the pads open, since this shifts effort away from the glute medius and reduces the exercise\'s effectiveness.', videoId: '5O_Y9l__iao' },

  plank: { name: 'Plank', muscle: 'Core', compound: false, restBase: 45, pattern: 'plank', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 30, repHi: 60, trackingMode: 'time', cue: 'Start face down and prop yourself up on your forearms and toes, with elbows stacked directly under your shoulders and your body forming a straight line from head to heels. Engage your core, squeeze your glutes, and tuck your pelvis slightly to prevent your lower back from sagging toward the floor. Keep your neck neutral by looking at a spot on the floor a few inches in front of your hands, and breathe steadily rather than holding your breath. The most common mistake is letting your hips sag or piking them up too high - both take tension off the core, so focus on maintaining that straight-line position for the full duration.', videoId: 'mwlp75MS6Rg' },
  hanging_leg_raise: { name: 'Hanging Leg Raise', muscle: 'Core', compound: false, restBase: 60, pattern: 'leg_raise', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 10, repHi: 15, cue: 'Hang from a pull-up bar with an overhand grip, hands roughly shoulder-width apart, and let your body hang straight down with a slight bend in the knees. Without swinging or using momentum, engage your abs to raise your legs up in front of you, aiming to bring them at least to hip height or higher for a fuller range of motion. Lower your legs back down slowly and under control rather than letting them drop, keeping tension on your core throughout the descent. Avoid using your hip flexors and momentum to swing the weight up - the movement should be driven by curling your pelvis and contracting your abs, not by kipping your legs.', videoId: 'vwl68EF9M2Q' },
  cable_crunch: { name: 'Cable Crunch', muscle: 'Core', compound: false, restBase: 60, pattern: 'crunch', equip: [{ v: 'cable', label: 'Cable' }], repLo: 12, repHi: 15, cue: 'Attach a rope handle to a high pulley and kneel a couple of feet in front of the machine, holding the rope on either side of your head with your hands near your ears. Keeping your hips stationary and locked in place, crunch your torso down and forward by flexing your spine, bringing your elbows toward your knees. Squeeze your abs hard at the bottom of the movement before slowly returning to the starting position, maintaining tension on the abs rather than letting the weight pull you back up. A common mistake is pulling with the arms or hinging at the hips instead of flexing the spine, which shifts the work away from the abs and onto the arms and hip flexors.', videoId: '36HK6uPM_PQ' },
  ab_wheel_rollout: { name: 'Ab Wheel Rollout', muscle: 'Core', compound: false, restBase: 60, pattern: 'rollout', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 8, repHi: 12, cue: 'Kneel on a padded mat and grip the ab wheel handles with both hands directly under your shoulders. Brace your core hard and slowly roll the wheel forward, extending your body into a straight line while keeping your hips from sagging toward the floor. Stop just before you lose tension in your abs or your lower back begins to arch, then squeeze your core to pull the wheel back to the starting position. Keep your arms mostly locked out and let the movement come from your hips and shoulders extending together. Avoid letting your lower back sag or overextend, which shifts stress away from the abs and onto the spine.', videoId: 'j6lR4u193gE' },
  russian_twist: { name: 'Russian Twist', muscle: 'Core', compound: false, restBase: 45, pattern: 'twist', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'bodyweight', label: 'Bodyweight' }], repLo: 15, repHi: 20, cue: 'Sit on the floor with your knees bent and heels either lightly touching the ground or lifted for added difficulty, leaning your torso back to roughly a 45-degree angle. Clasp your hands together or hold a weight, and rotate your torso to tap the floor beside your hips, then rotate to the other side. Keep your chest lifted and spine long throughout rather than rounding forward, and drive the rotation from your obliques rather than just swinging your arms. Move at a controlled, deliberate tempo instead of rushing through reps for momentum. A common mistake is rounding the lower back or letting the shoulders slump, which reduces core engagement and adds unnecessary spinal stress.', videoId: 'IJDOoVyVjhc' },
  situp: { name: 'Sit-Up', muscle: 'Core', compound: false, restBase: 45, pattern: 'situp', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 15, repHi: 20, cue: 'Lie on your back with your knees bent, feet flat on the floor, and hands lightly resting behind your ears or crossed over your chest. Engage your core and curl your torso up and forward, leading with your chest until you\'re sitting upright, then lower back down under control. Keep your chin slightly tucked and avoid yanking your head forward with your hands, which can strain your neck. Exhale as you rise and focus on using your abdominal muscles rather than momentum to pull yourself up. A common mistake is anchoring the feet under something and using the hip flexors to fling the torso up, which takes tension off the abs.', videoId: 'iL06z9PWYs8' },

  kelso_shrug: { name: 'Kelso Shrug', muscle: 'Back', compound: false, restBase: 60, pattern: 'shrug_row', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }], repLo: 12, repHi: 15, cue: 'Set an adjustable bench to roughly a 30-45 degree incline and lie face-down on it with a dumbbell in each hand, arms hanging straight down toward the floor. Keeping a slight bend in your elbows, shrug your shoulder blades up and back, focusing on squeezing them together at the top rather than just lifting straight up. Pause briefly at the top of the contraction before lowering the weights back under control to a full stretch. Avoid using your arms to curl or row the weight; the movement should come purely from your shoulder blades. A common mistake is shrugging straight up like a standard shrug instead of pulling the shoulder blades back and together, which misses the rhomboids and mid-traps this variation is designed to target.', videoId: 'Qq1xT2Vs_SY' },
  barbell_shrug: { name: 'Barbell Shrug', muscle: 'Back', compound: false, restBase: 60, pattern: 'shrug', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }, { v: 'smith', label: 'Smith Machine' }], repLo: 10, repHi: 15, cue: 'Stand tall holding a barbell in front of your thighs with an overhand, shoulder-width grip, feet about hip-width apart. Keeping your arms straight and knees soft, elevate your shoulders straight up toward your ears as high as possible, then pause briefly at the top before lowering the bar back down under control. Avoid rolling your shoulders forward or backward during the movement; the motion should be a straight vertical shrug to properly load the trapezius. Do not use momentum or bend your elbows to help hoist the weight, as this shifts work away from the traps. A common mistake is using too much weight and only performing a partial range of motion, which limits the stretch and contraction that build trap size.', videoId: 'KbsQ1E8Hg0o' },
  pendlay_row: { name: 'Pendlay Row', muscle: 'Back', compound: true, restBase: 100, pattern: 'row', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Set up with a loaded barbell on the floor, hinge at the hips until your torso is roughly parallel to the ground, and grip the bar just outside shoulder width. Starting from a dead stop on the floor each rep, explosively pull the bar up to your lower chest, driving your elbows back and squeezing your shoulder blades together. Lower the bar back to the floor under control and reset your position before starting the next rep, rather than bouncing the bar off the ground. Keep your spine neutral and torso angle fixed throughout the pull instead of using body english to heave the weight up. A common mistake is rounding the lower back or letting the hips rise as you pull, which turns the row into a sloppy deadlift-row hybrid.', videoId: 'h4nkoayPFWw' },
  seal_row: { name: 'Seal Row', muscle: 'Back', compound: true, restBase: 90, pattern: 'row', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Lie face-down on a bench set at chest height, elevated enough that your feet and torso hang free without touching the floor, and grip a barbell or dumbbells beneath you. Row the weight straight up toward your ribcage by driving your elbows back and squeezing your shoulder blades together, then lower it back to a full stretch under control. Because your torso is fully supported, resist the urge to jerk or use leg drive, and instead let your back muscles alone move the weight. Keep your head in a neutral position rather than craning it up to see the weight. A common mistake is choosing too much weight and only completing a partial range of motion, since the chest-supported setup makes cheating obvious and ineffective.', videoId: 'h5yD1pvXPKE' },
  meadows_row: { name: 'Meadows Row', muscle: 'Back', compound: true, restBase: 90, pattern: 'row', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 10, repHi: 12, cue: 'Set up a barbell in a landmine attachment, or wedge one end securely into a corner, and stand alongside it in a staggered stance, gripping close to the loaded end with one hand. Hinge forward at the hips with a flat back, and row the bar up and back toward your hip, driving your elbow high and squeezing your lat and upper back at the top. Lower the weight back down under control to a full stretch before starting the next rep. Keep your torso angle steady and avoid twisting your spine to generate momentum for the pull. A common mistake is standing too upright or rowing straight up instead of back toward the hip, which reduces lat engagement and turns it into more of a shrug.', videoId: 'g5Wlw-k8fek' },
  cable_pullover: { name: 'Cable Pullover', muscle: 'Back', compound: false, restBase: 60, pattern: 'pullover', equip: [{ v: 'cable', label: 'Cable' }], repLo: 12, repHi: 15, cue: 'Attach a straight bar or rope to a high pulley and stand or kneel facing the machine, gripping the attachment with arms extended overhead. Keeping your arms almost straight with only a slight bend in the elbows, pull the bar down and back in an arcing path until your hands reach roughly your thighs, focusing on driving the movement through your lats. Pause briefly and squeeze your lats at the bottom before allowing the weight to return under control to the overhead starting position. Avoid bending your elbows significantly, which turns the movement into a triceps pushdown, and keep your core braced so your lower back doesn\'t arch as you pull. A common mistake is using too much weight, which shortens the range of motion and shifts tension away from the lats.', videoId: '0RbPsrFfP0c' },
  snatch_grip_deadlift: { name: 'Snatch-Grip Deadlift', muscle: 'Back', compound: true, restBase: 180, pattern: 'hinge', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 5, repHi: 8, cue: 'Stand over a loaded barbell with a wide, snatch-width overhand grip, roughly where your forearms are vertical when you hinge down to the bar. Set your hips down, chest up, and spine neutral, then drive through your heels to stand up, keeping the bar close to your shins and thighs throughout the pull. Lock out by squeezing your glutes at the top rather than leaning back excessively. Because the wider grip increases the range of motion, focus on maintaining a tight upper back and neutral spine instead of letting your back round as the bar leaves the floor. A common mistake is letting the hips shoot up faster than the chest at the start of the pull, which turns the lift into a stiff-legged deadlift and stresses the lower back.', videoId: 'r5eT5DUfzww' },
  deficit_deadlift: { name: 'Deficit Deadlift', muscle: 'Back', compound: true, restBase: 180, pattern: 'hinge', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 5, repHi: 8, cue: 'Stand on a small platform, such as a plate or low block typically one to three inches high, with the barbell over your mid-foot, increasing the range of motion compared to a standard deadlift. Hinge at the hips and bend your knees to grip the bar, set your chest up and spine neutral, then drive through the floor to stand up while keeping the bar tight against your shins. Because the added deficit increases the demand on your starting position, take extra care to set your lats tight and hips at the proper height before initiating the pull. Move the bar in as straight a vertical line as possible rather than letting it drift away from your body. A common mistake is using too large a deficit or too much weight before you can maintain a neutral spine off the floor, which causes the lower back to round at the bottom of the lift.', videoId: 'hnuPZZfeRzs' },

  landmine_press: { name: 'Landmine Press', muscle: 'Shoulders', compound: true, restBase: 90, pattern: 'landmine_press', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 10, repHi: 12, cue: 'Load one end of a barbell into a landmine attachment, or wedge it securely into a corner, and hold the loaded end at shoulder height with one hand, standing in a staggered or half-kneeling stance. Press the bar up and slightly forward along its natural arcing path until your arm is extended, then lower it back to your shoulder under control. Brace your core throughout to prevent your torso from twisting or leaning excessively to one side as you press. Keep your wrist stacked over your elbow rather than letting it collapse backward under the load. A common mistake is pressing straight up as if it were an overhead press instead of following the bar\'s natural forward arc, which puts unnecessary strain on the shoulder.', videoId: '3gYz0bLG-wY' },
  behind_neck_press: { name: 'Behind-the-Neck Press', muscle: 'Shoulders', compound: true, restBase: 100, pattern: 'overhead_press', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 8, repHi: 10, cue: 'Sit or stand with a barbell racked behind your neck across your upper traps, gripping the bar wider than shoulder width to accommodate the position. Press the bar straight overhead until your arms are fully extended, then lower it back down slowly and under control to just below the base of your skull. Because this position places significant demand on shoulder mobility, only descend as low as you can without your shoulders rounding forward or your neck jutting forward to compensate. Keep your core braced and avoid arching your lower back to help drive the weight up. A common mistake is forcing a full range of motion despite limited shoulder mobility, which can place excessive stress on the rotator cuff, so this movement should only be attempted by lifters with adequate overhead mobility.', videoId: 'IoNod91DYgo' },

  zercher_squat: { name: 'Zercher Squat', muscle: 'Quads', compound: true, restBase: 150, pattern: 'squat', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Set a barbell in a rack at about hip height and cradle it in the crooks of your elbows, holding your forearms crossed or hands clasped in front of your chest to secure the bar against your body. Unrack the bar, step back, and set your feet shoulder-width apart, then squat down by pushing your hips back and bending your knees while keeping your torso as upright as possible. Drive through your heels to stand back up, keeping the bar close to your body throughout the movement. Brace your core hard, since the front-loaded position demands significant trunk stability to prevent leaning forward. A common mistake is letting the elbows drift outward or the torso collapse forward at the bottom, which shifts the load off the legs and strains the lower back.', videoId: 'JiAmqNV15xU' },
  sissy_squat: { name: 'Sissy Squat', muscle: 'Quads', compound: false, restBase: 60, pattern: 'sissy_squat', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 10, repHi: 15, cue: 'Stand holding onto a stable support like a squat rack or door frame for balance, with your feet hip-width apart and heels slightly raised off the ground. Rise onto the balls of your feet, then bend your knees and lean your torso back as you lower your body, keeping a straight line from your knees through your shoulders, until you feel a deep stretch in your quads. Push through the balls of your feet and contract your quads to pull yourself back up to the starting position. Keep your hips extended throughout rather than folding at the waist, which keeps tension isolated on the quadriceps. A common mistake is bending forward at the hips like a regular squat instead of leaning back with the body in a straight line, which turns the exercise into something closer to a lunge and reduces quad isolation.', videoId: '4Y30vn1IIe8' },
  cossack_squat: { name: 'Cossack Squat', muscle: 'Quads', compound: true, restBase: 75, pattern: 'lateral_squat', equip: [{ v: 'bodyweight', label: 'Bodyweight' }, { v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Stand with your feet set wider than shoulder width, toes turned slightly outward, holding a weight like a kettlebell or dumbbell at chest level for counterbalance if desired. Shift your weight onto one leg and bend that knee to sink your hips down and back, keeping your other leg straight with the foot flat and toes pointing up as you sink into the lateral lunge. Keep your chest up and the bent knee tracking over your toes as you descend as low as your hip mobility allows, then drive through the bent leg to return to standing. Avoid letting the bent knee cave inward or rounding your back to reach greater depth. A common mistake is rushing the movement or forcing extra depth beyond your current mobility, which compromises the straight leg\'s hamstring and adductor stretch and can strain the knee.', videoId: 'JaCbmoDqUc4' },
  sled_push: { name: 'Sled Push', muscle: 'Quads', compound: true, restBase: 90, pattern: 'sled', equip: [{ v: 'machine', label: 'Machine' }], repLo: 1, repHi: 1, cue: 'Load a sled with the appropriate weight and get into a low, athletic stance behind it, gripping the high or low handles depending on the desired torso angle. Drive forward by taking short, powerful steps, extending through your hips, knees, and ankles with each push, keeping your back flat and core braced. Keep your arms relatively locked with your shoulders positioned over or slightly behind the handles rather than letting them collapse forward. Maintain a consistent, driving stride rather than short choppy steps that lose power. A common mistake is standing too upright and pushing mostly with the arms, which removes leg drive and reduces the exercise\'s effectiveness for building lower-body power.', videoId: 'YJbKlXj4WhI' },

  nordic_curl: { name: 'Nordic Curl', muscle: 'Hamstrings', compound: false, restBase: 75, pattern: 'leg_curl', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 6, repHi: 10, cue: 'Kneel on a padded surface with your ankles securely anchored under a heavy object, a partner\'s hands, or a Nordic curl bench attachment. Keeping your body in a straight line from knees to head and your hips extended, slowly lower your torso toward the floor by resisting with your hamstrings for as long as possible. Catch yourself with your hands as you approach the floor if needed, then push back up or use your hands to assist the return to the starting kneeling position. Keep your hips extended throughout the descent rather than folding at the waist, which keeps the tension on the hamstrings rather than shifting it to the hip flexors. A common mistake is bending at the hips as you lower, which turns the movement into a controlled fall rather than a true hamstring-driven eccentric contraction.', videoId: 'nn743teTMTc' },
  reverse_hyper: { name: 'Reverse Hyper', muscle: 'Hamstrings', compound: true, restBase: 75, pattern: 'back_extension', equip: [{ v: 'machine', label: 'Machine' }], repLo: 12, repHi: 15, cue: 'Position your hips over the pad of a reverse hyper machine, or lie face-down on a sturdy bench with your hips at the edge for a bodyweight variation, and grip the handles or bench edge for stability, letting your legs hang down toward the floor. Using your glutes and hamstrings, swing your legs up and back until your body forms a straight line, or slightly beyond, then lower them back down under control to the starting position. Keep the movement controlled rather than using momentum to swing the legs, and avoid hyperextending your lower back at the top of the movement. Focus on initiating the motion from your glutes rather than jerking with your lower back. A common mistake is using excessive weight or momentum, which turns the exercise into an uncontrolled swing that can stress the lumbar spine instead of a controlled posterior-chain movement.', videoId: 'cZSxxPkCDy0' },

  farmers_carry: { name: 'Farmer’s Carry', muscle: 'Core', compound: true, restBase: 75, pattern: 'carry', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'trapbar', label: 'Trap Bar' }], repLo: 1, repHi: 1, cue: 'Stand tall between two heavy dumbbells or farmer\'s handles, hinge at the hips to grip them with a neutral wrist, and drive through your heels to stand up fully before you start walking. Keep your shoulders pulled back and down, your ribcage stacked over your pelvis, and brace your core hard as if bracing for a punch throughout the carry. Take controlled, deliberate steps rather than rushing, keeping the weights close to your sides without letting them swing. Avoid letting your shoulders round forward or hike up toward your ears, and don\'t let your torso lean or shift to one side to compensate for grip fatigue. Set the weights down with control at the end of the distance rather than dropping them.', videoId: 'lLAw6fUccKA' },
  suitcase_carry: { name: 'Suitcase Carry', muscle: 'Core', compound: true, restBase: 60, pattern: 'carry', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 1, repHi: 1, cue: 'Stand next to a heavy dumbbell or kettlebell, hinge down with a flat back to pick it up in one hand, and stand fully upright before moving. Keep your torso stacked vertically and resist the pull of the weight by bracing your obliques hard so your spine stays perfectly upright, not leaning away from the load. Walk with short, controlled steps, keeping both shoulders level and square to the front. The key cue is to imagine a broomstick running down your spine that your head, ribs, and hips can\'t tilt away from. Avoid letting your loaded-side shoulder drop or your hips shift sideways, since this shifts the work away from your core and onto your low back.', videoId: 'y-hn_Ha1-RE' },
  pallof_press: { name: 'Pallof Press', muscle: 'Core', compound: false, restBase: 45, pattern: 'anti_rotation', equip: [{ v: 'cable', label: 'Cable' }, { v: 'band', label: 'Band' }], repLo: 12, repHi: 15, cue: 'Attach a resistance band or cable at chest height and stand perpendicular to the anchor point with feet shoulder-width apart and knees slightly bent. Hold the handle at your sternum with both hands, brace your core, and press it straight out in front of you until your arms are fully extended, resisting the pull that wants to rotate your torso toward the anchor. Pause for a second at full extension before pulling the handle back to your chest under control. The key cue is to keep your hips and shoulders square the entire time, since the whole point of the exercise is preventing rotation, not creating it. Avoid leaning back or twisting your torso toward the machine to complete the press, as that defeats the anti-rotation purpose of the movement.', videoId: '_2xWmYNnFS8' },
  copenhagen_plank: { name: 'Copenhagen Plank', muscle: 'Core', compound: false, restBase: 60, pattern: 'plank', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 20, repHi: 40, trackingMode: 'time', cue: 'Lie on your side with your top foot propped on a bench and your bottom forearm on the floor directly under your shoulder, stacking your body in a straight line. Lift your hips off the floor by squeezing your top-leg adductors and bottom-leg glute, holding your bottom leg either bent for a short-lever regression or straight for the full long-lever version. Keep your body rigid from shoulders to ankles and breathe steadily rather than holding your breath through the hold. The key cue is to actively pull the bench toward you with your top inner thigh rather than just balancing on it. Avoid letting your hips sag toward the floor or rotate forward, which shifts load off the adductors and onto your shoulder and lower back.', videoId: 'YRRnnZsRs9U' },

  spider_curl: { name: 'Spider Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'ezbar', label: 'EZ-Bar' }], repLo: 10, repHi: 12, cue: 'Lean chest-first over the angled pad of a spider curl bench or steeply set incline bench, letting both arms hang straight down while holding a barbell or pair of dumbbells. Curl the weight up by flexing only at the elbow, squeezing hard at the top without letting your upper arms drift forward off the pad. Lower the weight slowly and fully to get a deep stretch at the bottom before starting the next rep. The key cue is that the chest support eliminates any body momentum, so the biceps should do all the work through the full range. Avoid rushing the eccentric or letting your elbows flare out to the sides, both of which reduce tension on the biceps.', videoId: 'jFxs5x0cAX8' },
  zottman_curl: { name: 'Zottman Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Stand holding a dumbbell in each hand at your sides with your palms facing forward and your elbows tucked close to your torso. Curl both dumbbells up with a supinated, palms-up grip just like a standard bicep curl, then at the top rotate your wrists so your palms face down before lowering the weights slowly in this pronated position. The key cue is to make the lowering phase slow and controlled, since that pronated eccentric is what builds forearm and grip strength on top of the biceps work. Avoid swinging the dumbbells up with momentum or letting your elbows drift forward, which shifts tension away from the target muscles. Rotate your wrists again at the bottom to return to the palms-up starting position for the next rep.', videoId: 'KhXiqxGxu1s' },

  jm_press: { name: 'JM Press', muscle: 'Triceps', compound: false, restBase: 75, pattern: 'close_grip_bench', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'ezbar', label: 'EZ-Bar' }], repLo: 8, repHi: 10, cue: 'Lie on a flat bench and unrack a barbell, or use a Smith machine, with a shoulder-width close grip, holding it straight over your upper chest. Lower the bar in a hybrid path between a close-grip bench press and a skull crusher, aiming your elbows toward your feet and bringing the bar down toward your chin or upper chest while keeping your upper arms relatively fixed. Just before the bar touches, drive it back up by extending your elbows and pressing through your triceps, without turning the movement into a full bench press. The key cue is to keep your elbows tucked and pointed forward rather than flaring them out, which keeps tension on the triceps. Avoid using too much weight early on, since the joint angle is unfamiliar and puts significant stress on the elbows if form breaks down.', videoId: '8MdRd9j2EUg' },
  larsen_press: { name: 'Larsen Press', muscle: 'Chest', compound: true, restBase: 110, pattern: 'bench_press', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 8, repHi: 10, cue: 'Lie flat on a bench and lift your legs straight up or let them hang off the end of the bench so your feet lose contact with the floor entirely, removing leg drive from the lift. Unrack the barbell with a normal bench grip and lower it under control to your mid-chest, keeping your shoulder blades pinned back and down against the bench. Press the bar back up in a straight line, relying purely on upper-body strength and core bracing to stabilize the bar path since your legs can\'t help. The key cue is to brace your abs hard as if bracing for a punch, since your core is now doing the stabilizing job your legs normally would. Avoid arching your lower back excessively or letting your hips lift off the bench to compensate for the lost leg drive.', videoId: 'FwO2j6bBHpw' },

  // Added from free-exercise-db (github.com/yuhonas/free-exercise-db, public domain/Unlicense) —
  // curated subset of the strength/plyometric entries, mapped into this app's schema (muscle
  // taxonomy, equipment variants merged per movement, rep/rest defaults heuristic since the
  // source has neither), capped per muscle to keep this an addition rather than a bulk replace of
  // the hand-curated library above. cue text is adapted from the source's own instructions.
  reverse_crunch: { name: 'Reverse Crunch', muscle: 'Core', compound: false, restBase: 60, pattern: 'crunch', equip: [{ v: 'cable', label: 'Cable' }, { v: 'bodyweight', label: 'Bodyweight' }], repLo: 10, repHi: 12, cue: 'Lie on your back with your arms at your sides or holding a bench behind your head for stability, and bring your knees up toward your chest so your hips and knees start at roughly 90 degrees. Curl your hips and pelvis up off the floor by contracting your lower abs, drawing your knees toward your chest rather than just swinging your legs. Lower your hips back down with control until they just touch the floor, without letting your feet drop all the way to full extension between reps. The key cue is to initiate the movement from your pelvis curling, not from momentum generated by swinging your legs. Avoid using your hip flexors to fling your legs up, which is the most common way people cheat this exercise and take tension off the abs.', videoId: 'nYcE7-Dhpzk' },
  ab_rollout: { name: 'Ab Rollout', muscle: 'Core', compound: true, restBase: 120, pattern: 'rollout', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Kneel on a padded surface holding an ab wheel with both hands directly under your shoulders, starting with your torso upright and your core braced. Slowly roll the wheel forward, extending your body into a long line while keeping your hips from sagging and your lower back from arching, going only as far as you can control. Once you reach your limit of control, reverse the motion by contracting your abs and pulling the wheel back toward your knees to return to the start. The key cue is to keep a slight posterior pelvic tilt throughout so your core, not your lower back, controls the extension. Avoid letting your hips drop toward the floor at the bottom of the rollout, which is the most common form breakdown and puts excessive stress on the lumbar spine.', videoId: 'NbudTqiwguk' },
  ab_rollout_on_knees: { name: 'Ab Rollout - On Knees', muscle: 'Core', compound: true, restBase: 120, pattern: 'rollout', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Kneel on a mat with an ab wheel positioned directly beneath your shoulders and your hips stacked over your knees to start. Brace your core hard and roll the wheel forward only as far as you can keep your spine in a straight, neutral line from shoulders to hips, stopping well short of full extension as a beginner. Pause briefly at your furthest controlled point, then squeeze your abs to pull the wheel back to the starting position rather than letting momentum or your hip flexors do the work. The key cue is to limit the range of motion to what you can control with your core rather than chasing distance, since the kneeling variation is a progression toward the full standing rollout. Avoid arching your lower back as you roll out, which is a sign you\'ve gone past your current strength level.', videoId: 'EYY9yXWcpOY' },
  bent_press: { name: 'Bent Press', muscle: 'Core', compound: true, restBase: 120, pattern: 'overhead_press', equip: [{ v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Clean a kettlebell to the rack position at your shoulder, then set your feet with the working-side foot turned slightly out and the other foot set back and turned further out for stability. Keeping your eyes on the kettlebell the entire time, bend sideways at the hip away from the weight while pressing the floor away with a long, locked-out arm, essentially screwing your body down and under the bell rather than pressing it up with your shoulder. Keep the weighted arm locked and vertical throughout, letting your torso do the work of moving your body underneath the bell. The key cue is to move your hips, not your shoulder, treating this more like a weighted side bend with a fixed arm than a press. Avoid rushing the descent or losing tightness in your core, since a loss of tension at any point in this complex lift is what leads to injury.', videoId: 'DswWXZ2wsvI' },
  cross_body_crunch: { name: 'Cross-body Crunch', muscle: 'Core', compound: true, restBase: 90, pattern: 'crunch', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 8, repHi: 10, cue: 'Lie on your back with your knees bent and feet flat on the floor, placing your hands lightly behind your head without interlocking your fingers. Crunch up and rotate your torso to bring one elbow diagonally across your body toward the opposite knee, while that knee can lift slightly to meet it. Lower back down with control and repeat on the other side, alternating in a smooth, continuous rhythm. The key cue is to initiate the rotation from your ribcage and obliques, not by yanking your neck with your hands. Avoid using your hands to pull your head forward, which strains the neck instead of working the obliques.', videoId: 'S3a-uB-GQWo' },
  decline_oblique_crunch: { name: 'Decline Oblique Crunch', muscle: 'Core', compound: true, restBase: 90, pattern: 'crunch', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 8, repHi: 10, cue: 'Secure your feet under the pads of a decline bench and lie back with your torso angled downward, optionally holding a weight plate against your chest for added resistance. Crunch up while rotating your torso to one side, driving your ribcage toward the opposite hip, then lower back down under control to the start. Alternate sides evenly, or complete all reps on one side before switching, depending on your program. The key cue is to lead the twist with your obliques rather than swinging your shoulders or using your arms to generate momentum. Avoid yanking yourself up using your hip flexors or bouncing at the bottom of the decline, both of which shift work away from the abs and add strain to the lower back.', videoId: 'QM9iwYWUouo' },
  decline_reverse_crunch: { name: 'Decline Reverse Crunch', muscle: 'Core', compound: true, restBase: 90, pattern: 'crunch', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 8, repHi: 10, cue: 'Lie face-up on a decline bench with your head toward the top and grip the handles or the top edge of the bench behind your head for stability. With your knees bent, curl your hips up off the bench by drawing your knees toward your chest, using your lower abs to lift against the added resistance of the decline angle. Lower your hips back down slowly until your legs are near straight, stopping before your lower back arches off the bench. The key cue is to keep the movement slow and controlled given the extra decline resistance, since momentum is easier to use here than on a flat reverse crunch. Avoid letting your lower back arch away from the bench at the bottom, which signals you\'ve lowered further than your core strength currently supports.', videoId: 'YcMj0EEadQo' },
  jackknife_sit_up: { name: 'Jackknife Sit-up', muscle: 'Core', compound: true, restBase: 90, pattern: 'situp', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 8, repHi: 10, cue: 'Lie flat on your back with your arms extended straight overhead and your legs straight out on the floor. In one controlled motion, simultaneously lift your torso and your legs, reaching your hands toward your toes so your body folds at the hips like a jackknife. Squeeze your abs hard at the top where your hands meet your feet, then lower both your torso and legs back down together with control. The key cue is to keep the upward and downward motion synchronized between your upper and lower body rather than sitting up first and then lifting the legs. Avoid using momentum to fling yourself up or letting your lower back arch as you lower down, since both increase strain on the spine.', videoId: 'GEZ8NLbtc8Q' },
  press_sit_up: { name: 'Press Sit-up', muscle: 'Core', compound: true, restBase: 120, pattern: 'situp', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Lie on your back holding a dumbbell in each hand at shoulder height, with your knees bent and feet anchored or flat on the floor. Perform a full sit-up by curling your torso up off the floor, and as you reach the top, press both dumbbells straight overhead until your arms are fully extended. Lower the dumbbells back to shoulder height as you simultaneously lower your torso back down to the floor with control. The key cue is to keep your core braced throughout the press portion so the movement doesn\'t turn into a lower-back-driven heave. Avoid using momentum from swinging the dumbbells to help you sit up, and don\'t let your lower back slam into the floor on the way down.', videoId: 'IdwmoMQ1fx8' },
  bicep_curl: { name: 'Bicep Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Stand tall holding a dumbbell or barbell in each hand with your arms fully extended at your sides and your elbows tucked close to your torso. Curl the weight up by flexing at the elbow only, keeping your upper arms pinned in place and squeezing the biceps hard at the top of the movement. Lower the weight back down slowly and under control until your arms are fully extended again. The key cue is to keep your elbows stationary throughout the entire rep, letting only your forearms move. Avoid swinging the weight up using your hips and shoulders or letting your elbows drift forward, both of which turn the exercise into momentum rather than a true bicep contraction.', videoId: 'XE_pHwbst04' },
  // These four were imported from free-exercise-db as 'Biceps' because the taxonomy had no
  // Forearms muscle at the time (see CLAUDE.md's import notes) — re-tagged in phase 32 when
  // Forearms became a real muscle.
  palms_down_wrist_curl_over_a_bench: { name: 'Palms-down Wrist Curl Over A Bench', muscle: 'Forearms', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Sit on a bench holding a barbell or pair of dumbbells with an overhand, palms-down grip, and rest your forearms on your thighs or the bench with your wrists hanging just off the edge. Let the weight roll down toward your fingertips first, allowing your wrist to extend fully, then curl it back up by flexing your wrist as high as it will go. Keep your forearms pressed firmly against the bench throughout so only your wrists are moving. The key cue is to use a slow, deliberate tempo and a light weight, since the wrist extensors are a small muscle group that fatigues quickly. Avoid lifting your forearms off the bench or using your elbows to help hoist the weight, which takes tension off the forearms.', videoId: 's1MHtPsi8vY' },
  palms_up_wrist_curl_over_a_bench: { name: 'Palms-up Wrist Curl Over A Bench', muscle: 'Forearms', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Kneel behind a flat bench and rest your forearms on top with your wrists and hands hanging off the edge, gripping a barbell with an underhand (palms-up) grip at shoulder width. Curl the bar upward using only your wrists, squeezing your forearms hard at the top, then slowly lower it until your wrists are fully extended and you feel a stretch. Keep your forearms pinned to the bench throughout the set so the movement comes entirely from the wrist joint, not the elbows or shoulders. Avoid using momentum or bouncing the bar out of the bottom position, as this shifts tension away from the forearm flexors and increases strain on the wrists.', videoId: 'dQtMZ3ZEGwU' },
  reverse_curl: { name: 'Reverse Curl', muscle: 'Forearms', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'cable', label: 'Cable' }], repLo: 10, repHi: 12, cue: 'Stand tall holding a barbell or EZ-bar with an overhand (pronated) grip, hands shoulder-width apart and arms fully extended in front of your thighs. Keeping your elbows tucked close to your sides, curl the bar upward toward your chest by flexing at the elbow, then lower it back down under control to full extension. Focus on keeping your wrists flat and rigid rather than letting them curl inward, since the exercise is meant to load the brachioradialis and forearm extensors as well as the biceps. Avoid swinging your torso or flaring your elbows out to move heavier weight, as this is a lighter-load movement that rewards strict form.', videoId: 'pXx38ZWRYjo' },
  seated_palms_down_wrist_curl: { name: 'Seated Palms-down Wrist Curl', muscle: 'Forearms', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Sit on a bench and rest your forearms on your thighs or on the bench itself with your wrists and hands hanging just past your knees, holding a barbell or dumbbells with an overhand (palms-down) grip. Let the weight lower your hands into full wrist flexion, then curl your knuckles upward as high as possible by extending your wrists, squeezing at the top. Move slowly and deliberately through a full range of motion, since this exercise targets the wrist extensors and is easy to cheat with momentum. Avoid lifting your forearms off your legs or using your elbows to help hoist the weight, as that shifts work away from the wrists.', videoId: 'uXNUT1AD3JY' },
  drag_curl: { name: 'Drag Curl', muscle: 'Biceps', compound: true, restBase: 120, pattern: 'curl', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Stand holding a barbell with an underhand shoulder-width grip, arms extended and the bar resting against your thighs. Instead of curling the bar away from your body like a standard curl, drag it straight up along your torso by driving your elbows back and up behind you, keeping the bar in contact with your body the whole way. This altered bar path shifts emphasis onto the long head of the biceps and reduces front-deltoid involvement, so keep your shoulders pinned back and avoid letting the bar swing forward. A common mistake is turning it into a normal curl by pushing the bar out and away from the torso, which defeats the purpose of the drag path.', videoId: 'K1baXRg-OG8' },
  high_curls: { name: 'High Curls', muscle: 'Biceps', compound: true, restBase: 90, pattern: 'curl', equip: [{ v: 'cable', label: 'Cable' }], repLo: 8, repHi: 10, cue: 'Set a cable pulley low on either side (or hold dumbbells) and raise your arms out to the sides at roughly shoulder height so your upper arms are parallel to the floor. From this raised position, curl your hands up toward your shoulders by flexing at the elbow while keeping your upper arms locked in place and stationary. Squeeze the biceps hard at the top of each rep before lowering back to the starting extended position with control. Avoid dropping your elbows or letting your upper arms drift forward during the curl, since keeping them elevated and fixed is what makes this variation target the biceps peak differently than a standard curl.', videoId: '-WKKdI7dhwA' },
  alternate_bicep_curl: { name: 'Alternate Bicep Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Stand holding a dumbbell in each hand at your sides with palms facing your thighs, feet shoulder-width apart and core braced. Curl one dumbbell upward while rotating your forearm so your palm faces your shoulder at the top, squeeze briefly, then lower it under control as you begin curling the opposite arm. Keep your upper arms and elbows pinned to your sides throughout so the movement is isolated to the elbow joint rather than the shoulders. Avoid swinging your torso or using momentum to heave the dumbbell up, since alternating sides makes it tempting to rock your body for extra leverage.', videoId: 'nBzLCE-dcRQ' },
  alternate_hammer_curl: { name: 'Alternate Hammer Curl', muscle: 'Biceps', compound: false, restBase: 60, pattern: 'curl', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Stand holding a dumbbell in each hand with a neutral grip, palms facing your torso, arms extended at your sides. Curl one dumbbell straight up toward your shoulder while keeping your palm facing inward the entire time, then lower it slowly as you curl the other arm, alternating in a controlled rhythm. Keep your elbows tucked close to your ribs and your wrists straight, since the neutral grip is what shifts extra emphasis onto the brachialis and brachioradialis alongside the biceps. Avoid letting your elbows drift forward or swinging the dumbbells with your hips to move more weight than you can control.', videoId: 'YKJIOM6CM0o' },
  one_arm_upright_row: { name: 'One-arm Upright Row', muscle: 'Shoulders', compound: true, restBase: 90, pattern: 'row', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'machine', label: 'Machine' }], repLo: 6, repHi: 8, cue: 'Stand holding a single dumbbell in one hand in front of your thigh with an overhand grip, feet shoulder-width apart and your free hand resting on a support for stability. Pull the dumbbell straight up along the front of your body by leading with your elbow, raising it above shoulder height until your upper arm is roughly parallel to the floor. Keep the dumbbell close to your torso throughout the pull and let your elbow travel higher than your wrist at the top. Avoid shrugging heavily through your traps or raising the elbow past a comfortable range at the shoulder, since going too high can pinch the shoulder joint.', videoId: 'KZUf1_JjTZo' },
  seated_press: { name: 'Seated Press', muscle: 'Shoulders', compound: true, restBase: 90, pattern: 'overhead_press', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Sit on a bench with back support, holding a barbell or a pair of dumbbells at shoulder height with your palms facing forward and feet flat on the floor. Press the weight straight overhead until your arms are fully extended, then lower it back down under control to the starting position at shoulder level. Keep your core braced and your lower back flat against the pad to avoid excessive arching as you press. Avoid flaring your elbows too far forward or letting the weight drift behind your head, both of which put unnecessary stress on the shoulder joints.', videoId: 'YNK3eQVevIs' },
  reverse_flyes: { name: 'Reverse Flyes', muscle: 'Shoulders', compound: false, restBase: 60, pattern: 'rear_delt_fly', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Hold a dumbbell in each hand and hinge forward at the hips until your torso is close to parallel with the floor, letting your arms hang straight down with a slight bend in the elbows and palms facing each other. Keeping that slight elbow bend fixed, raise both arms out to the sides in a wide arc until they\'re roughly in line with your shoulders, squeezing your shoulder blades together at the top. Lower the dumbbells back down slowly under control to complete the rep. Avoid standing too upright or shrugging the weight up with your traps, since the movement should come from the rear deltoids and upper back rather than momentum or lower-back rounding.', videoId: '4Xr7bKE_fxE' },
  alternating_press: { name: 'Alternating Press', muscle: 'Shoulders', compound: true, restBase: 120, pattern: 'overhead_press', equip: [{ v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Sit or stand holding a dumbbell in each hand at shoulder height with palms facing forward and your core braced. Press one dumbbell straight overhead to full extension while the other stays locked at shoulder height, then lower the first as you press the second, alternating sides in a steady rhythm. Keep your torso upright and avoid leaning or twisting to help drive the weight up, since the asymmetrical load challenges core stability. A common mistake is rushing the tempo, which causes you to lose control of the descending dumbbell and arch your lower back for momentum.', videoId: '7a2LlkBPsqU' },
  alternating_shoulder_press: { name: 'Alternating Shoulder Press', muscle: 'Shoulders', compound: true, restBase: 90, pattern: 'overhead_press', equip: [{ v: 'cable', label: 'Cable' }], repLo: 8, repHi: 10, cue: 'Stand or sit with a dumbbell in each hand held at shoulder height, palms facing forward and elbows pointing slightly out in front of you. Press one dumbbell overhead to lockout while keeping the other stationary at the shoulder, then lower it as you press the opposite arm up, alternating continuously. Brace your core and glutes to keep your torso stable and avoid excessive side-to-side sway as the load shifts from one arm to the other. Avoid arching your lower back to help push the weight up; instead let the pressing arm do all the work while everything else stays rigid.', videoId: 'uMr1qYcrcfY' },
  anti_gravity_press: { name: 'Anti-gravity Press', muscle: 'Shoulders', compound: true, restBase: 120, pattern: 'overhead_press', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Stand holding a single dumbbell or kettlebell at shoulder height in one hand with a neutral or overhand grip, feet in a staggered or split stance for stability. Press the weight up and slightly across your body, then reverse the path back down to the shoulder in a slow, deliberate motion that emphasizes control over speed. Focus on decelerating the weight on the way down just as hard as you drive it up, since the exercise is designed to build strength through a controlled, resisted lowering phase. Avoid rushing the descent or letting the weight drop quickly, as losing tension on the way down defeats the purpose of the movement.', videoId: 'ONcMkctXfMI' },
  clean_and_press: { name: 'Clean And Press', muscle: 'Shoulders', compound: true, restBase: 120, pattern: 'overhead_press', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Start with a barbell or a pair of dumbbells on the floor in front of you, feet hip-width apart, hips hinged back and chest up as you grip the weight. Explosively extend your hips and knees to pull the weight upward, then quickly drop under it to catch it at shoulder height in a front-rack position before driving it overhead into a press to lockout. Keep the weight close to your body throughout the pull and transition smoothly from the clean into the press without pausing too long at the shoulders. Avoid rounding your lower back during the initial pull off the floor, since that\'s the most common and highest-risk mistake in this multi-joint movement.', videoId: 'KCe8l86-alA' },
  cuban_press: { name: 'Cuban Press', muscle: 'Shoulders', compound: true, restBase: 90, pattern: 'overhead_press', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 6, repHi: 8, cue: 'Stand holding a dumbbell in each hand at your sides, then raise your upper arms out to the sides until they\'re parallel to the floor with elbows bent 90 degrees, as if finishing an upright row. From there, rotate your forearms upward so the dumbbells rise until your arms form a goalpost shape, then press the dumbbells straight overhead to full lockout. Reverse the sequence carefully, lowering back through the rotation and then the upright-row position to complete one rep. Move slowly and use light weight, since the exercise is meant to build shoulder stability and rotator cuff control, and rushing through the rotation is the most common mistake that defeats its purpose.', videoId: 'e7gGRU0o-Q8' },
  double_push_press: { name: 'Double Push Press', muscle: 'Shoulders', compound: true, restBase: 120, pattern: 'overhead_press', equip: [{ v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Stand with a dumbbell in each hand racked at shoulder height, feet shoulder-width apart and knees soft. Dip slightly by bending your knees and hips a few inches, then explosively drive up through your legs while pressing both dumbbells overhead simultaneously to full lockout. Use the leg drive to help generate momentum for the initial part of the press, then finish by actively pressing the weights out with your arms until they\'re fully extended overhead. Avoid turning the movement into a strict press by skipping the leg dip, and avoid leaning back excessively to compensate, which strains the lower back.', videoId: 'DhSkCaVO-KE' },
  flyes: { name: 'Flyes', muscle: 'Chest', compound: false, restBase: 60, pattern: 'fly', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'ezbar', label: 'EZ-Bar' }], repLo: 10, repHi: 12, cue: 'Lie back on a flat bench holding a dumbbell in each hand directly above your chest, palms facing each other and a slight bend maintained in your elbows. Lower the dumbbells out to the sides in a wide arc, keeping that slight elbow bend fixed, until you feel a deep stretch across your chest, then reverse the arc and bring the dumbbells back together above your chest by squeezing your pecs. Keep the movement controlled and avoid letting the dumbbells drop too low or your elbows straighten, both of which put excess strain on the shoulder joint. Avoid turning the fly into a press by bending your elbows more as you lift, since that shifts work onto the triceps instead of the chest.', videoId: 'LzFvciCdoW0' },
  alternating_floor_press: { name: 'Alternating Floor Press', muscle: 'Chest', compound: true, restBase: 120, pattern: 'bench_press', equip: [{ v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Lie on your back on the floor with knees bent and feet flat, holding a dumbbell in each hand at chest level with your upper arms resting on the floor and forearms vertical. Press one dumbbell straight up until your arm is fully extended while the other stays at chest level resting on the floor, then lower it back down as you press the opposite arm, alternating continuously. Let your upper arms briefly touch the floor at the bottom of each rep to reset before pressing again, using the floor as a natural range-of-motion limiter that reduces shoulder strain. Avoid arching your lower back off the floor or bouncing the dumbbells off the ground for momentum, since both reduce the stability benefit of pressing anti-rotationally with one arm at a time.', videoId: 'wL7NClidGVE' },
  bench_press_medium_grip: { name: 'Bench Press - Medium Grip', muscle: 'Chest', compound: true, restBase: 120, pattern: 'bench_press', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Lie flat on a bench with your eyes roughly under the bar, feet planted firmly on the floor, and grip the barbell slightly wider than shoulder width so your forearms will be vertical at the bottom of the press. Unrack the bar over your chest, lower it under control to touch around mid-chest while keeping your elbows at roughly a 45-degree angle from your torso, then drive it back up to full lockout. Keep your shoulder blades retracted and pinned to the bench and maintain a slight natural arch in your lower back for a stable base. Avoid flaring your elbows out to 90 degrees or bouncing the bar off your chest, both of which increase shoulder strain and reduce control of the lift.', videoId: 'ukDEXCXJxdM' },
  bench_press_with_neutral_grip: { name: 'Bench Press With Neutral Grip', muscle: 'Chest', compound: true, restBase: 90, pattern: 'bench_press', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 6, repHi: 8, cue: 'Lie flat on a bench holding two dumbbells with your palms facing each other directly above your shoulders. Lower the dumbbells slowly along your sides until your upper arms are roughly parallel to the floor or you feel a light stretch in your chest, keeping your elbows tracking under your wrists rather than flaring out. Press the dumbbells back up and slightly in toward each other until your arms are extended but not locked out, squeezing your chest at the top. Keep your shoulder blades pinned back and down against the bench throughout to protect your shoulders and maximize chest tension. Avoid letting the dumbbells drift too far apart or bouncing them off your chest at the bottom, as this reduces control and shifts stress onto the shoulder joints.', videoId: 'Oq5MMAbUE2o' },
  chest_press: { name: 'Chest Press', muscle: 'Chest', compound: true, restBase: 90, pattern: 'bench_press', equip: [{ v: 'cable', label: 'Cable' }], repLo: 8, repHi: 10, cue: 'Sit in the chest press machine with your back flat against the pad and the handles positioned level with your mid-chest. Grip the handles and press them forward until your arms are extended without fully locking your elbows, then return slowly to the starting position with control. Keep your shoulder blades pulled back and down into the pad throughout the movement rather than letting them roll forward at the top. Exhale as you press and inhale as you return the handles. A common mistake is using momentum by bouncing at the start of each rep or letting the shoulders round forward, which shifts the load away from the chest and onto the front of the shoulder.', videoId: 'pLofEAcfsO8' },
  clock_push_up: { name: 'Clock Push-up', muscle: 'Chest', compound: true, restBase: 90, pattern: 'pushup', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 8, repHi: 10, cue: 'Start in a standard push-up position with your hands under your shoulders and body in a straight line from head to heels, imagining a clock face beneath your chest. Perform a push-up, then walk your hands slightly to the 12 o\'clock position, lower into another rep, and continue rotating your hand placement clockwise through each hour position after every rep. Keep your core braced and hips level throughout so your body doesn\'t sag or pike as your hand position shifts. Move deliberately between positions rather than rushing, since each new angle changes the emphasis across your chest, shoulders, and triceps. Avoid letting your lower back sag as fatigue sets in, which is the most common breakdown in form during this variation.', videoId: '7M-e8LMSE74' },
  decline_flyes: { name: 'Decline Flyes', muscle: 'Chest', compound: true, restBase: 90, pattern: 'fly', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 6, repHi: 8, cue: 'Lie back on a decline bench with your feet secured and hold a dumbbell in each hand directly above your lower chest, palms facing each other with a slight bend in your elbows. Lower the dumbbells out to your sides in a wide arc until you feel a deep stretch across your chest, keeping that slight elbow bend fixed throughout the movement. Reverse the arc by squeezing your chest to bring the dumbbells back together above your lower chest, rather than pressing them up as you would in a press. Keep the movement slow and controlled, especially at the bottom of the stretch, to avoid straining the shoulder joint. A common mistake is bending and straightening the elbows during the fly, which turns the movement into a press and takes tension off the chest.', videoId: 'IMALXhhHRKM' },
  decline_press: { name: 'Decline Press', muscle: 'Chest', compound: true, restBase: 90, pattern: 'bench_press', equip: [{ v: 'machine', label: 'Machine' }], repLo: 8, repHi: 10, cue: 'Secure your legs at the end of a decline bench and lie back, unracking the barbell with a medium-width overhand grip so it sits directly above your lower chest. Lower the bar slowly and under control until it lightly touches your lower chest, keeping your elbows at roughly a 45-degree angle from your torso. Drive the bar back up powerfully to the starting position, exhaling as you press. Keep your shoulder blades retracted and your feet locked under the leg pads for stability throughout the set. Because a spotter can\'t easily assist you on a decline bench, use a weight you can control safely and avoid flaring your elbows out to 90 degrees, which places excess stress on the shoulders.', videoId: 'LfyQBUKR8SE' },
  extended_range_one_arm_floor_press: { name: 'Extended Range One-arm Floor Press', muscle: 'Chest', compound: true, restBase: 120, pattern: 'bench_press', equip: [{ v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Lie on your back on the floor holding a single dumbbell or kettlebell in one hand, arm extended straight above your shoulder, with your knees bent and feet flat for stability. Position yourself so your working shoulder and upper arm can hang slightly off the edge of a mat or platform, letting your elbow travel below torso level for an extended range compared to a standard floor press. Lower the weight slowly until you feel a deep stretch in your chest and shoulder, then press it back up to full extension without letting your torso twist. Brace your core and keep your opposite arm out to the side for balance throughout the set. Avoid rushing the descent or letting the working shoulder roll forward, since the extra range makes control more important than the amount of weight used.', videoId: 'p_pf8S5vpTU' },
  bent_over_row: { name: 'Bent Over Row', muscle: 'Back', compound: true, restBase: 120, pattern: 'row', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'machine', label: 'Machine' }], repLo: 6, repHi: 8, cue: 'Stand with feet hip-width apart, hinge forward at the hips until your torso is roughly parallel to the floor, and grip a barbell with hands just outside shoulder width, letting it hang below your shoulders with a slight bend in the knees. Pull the bar up toward your lower ribcage by driving your elbows back and squeezing your shoulder blades together, then lower it under control back to the starting position. Keep your spine neutral and your core braced throughout so your torso doesn\'t rise and fall with each rep. Lead the pull with your elbows rather than your hands to keep the tension on your back muscles. A common mistake is standing too upright or using momentum to jerk the bar up, which shifts the work to the lower back and reduces tension on the lats.', videoId: 'rqTOAM8WoeM' },
  one_arm_row: { name: 'One-arm Row', muscle: 'Back', compound: true, restBase: 90, pattern: 'row', equip: [{ v: 'dumbbell', label: 'Dumbbell' }, { v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Place one knee and the same-side hand on a flat bench for support, keeping your back flat and roughly parallel to the floor, and hold a dumbbell in your free hand with your arm hanging straight down. Pull the dumbbell up toward your hip by driving your elbow back and up, keeping it close to your body, then lower it under control to a full stretch. Keep your torso still and avoid rotating your shoulders or twisting your spine as you pull. Squeeze your shoulder blade back at the top of each rep before lowering. Avoid using momentum or yanking the weight up with your lower back, since this reduces lat engagement and increases strain on the spine.', videoId: 'ze6J_KJtJJ8' },
  alternating_renegade_row: { name: 'Alternating Renegade Row', muscle: 'Back', compound: true, restBase: 120, pattern: 'row', equip: [{ v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Start in a high plank position with your hands gripping a pair of dumbbells directly under your shoulders and your feet set wide for a stable base. Row one dumbbell up toward your hip by driving your elbow back, keeping your hips and shoulders square to the floor, then lower it and repeat on the other side. Keep your core tightly braced throughout so your torso doesn\'t rotate or sag as you shift weight between arms. Move slowly and pause briefly at the top of each row to resist the urge to rock your hips. The most common mistake is letting your hips twist or drop toward the working side, which turns the exercise into a core-stability failure rather than a controlled row.', videoId: '87fIdMr0Ojs' },
  bent_over_one_arm_long_bar_row: { name: 'Bent Over One-arm Long Bar Row', muscle: 'Back', compound: true, restBase: 120, pattern: 'row', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Anchor one end of a landmine bar, or wedge a barbell securely in a corner, and load the free end, then stand to one side and hinge forward at the hips with a flat back. Grip the bar close to the loaded end with one hand and let it hang, then pull it up toward your hip by driving your elbow back, keeping your torso stable. Lower the bar under control back to a full stretch before starting the next rep. Keep your knees softly bent and your core braced to prevent your lower back from rounding. Avoid rotating your torso to help lift the weight, since the offset load makes it tempting to twist rather than row with your back muscles.', videoId: '6e-RoYjC6UQ' },
  bent_over_two_arm_long_bar_row: { name: 'Bent Over Two-arm Long Bar Row', muscle: 'Back', compound: true, restBase: 120, pattern: 'row', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Anchor one end of a landmine bar securely and stand over the loaded end with feet shoulder-width apart, hinging forward at the hips with a flat back until your torso is near parallel to the floor. Grip the bar with both hands close together near the sleeve and pull it up toward your torso by driving your elbows back and squeezing your shoulder blades together. Lower the bar under control to a full stretch before the next rep. Keep your core braced and your spine neutral throughout to protect your lower back in the bent-over position. A common mistake is rounding the back or using a hip drive to heave the weight up, which turns the row into a deadlift-like movement instead of isolating the back.', videoId: 'O2V58mCnmQc' },
  bent_over_two_dumbbell_row: { name: 'Bent Over Two-dumbbell Row', muscle: 'Back', compound: true, restBase: 90, pattern: 'row', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 6, repHi: 8, cue: 'Stand with feet shoulder-width apart holding a dumbbell in each hand, hinge forward at the hips until your torso is near parallel to the floor with a flat back and slightly bent knees. Let the dumbbells hang straight down, then pull them up toward your ribcage by driving your elbows back and squeezing your shoulder blades together at the top. Lower the dumbbells under control back to a full stretch before the next rep. Keep your neck in a neutral position, looking slightly ahead rather than straining upward. Avoid letting your torso rise toward vertical as you pull, since that shifts the effort away from your back and turns the row into a shrug.', videoId: '2MW94NxnGik' },
  bent_over_two_dumbbell_row_with_palms_in: { name: 'Bent Over Two-dumbbell Row With Palms In', muscle: 'Back', compound: true, restBase: 90, pattern: 'row', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 6, repHi: 8, cue: 'Stand with feet shoulder-width apart holding a dumbbell in each hand with your palms facing each other, then hinge forward at the hips until your torso is near parallel to the floor with a flat back. Row both dumbbells up along your sides toward your hips by driving your elbows straight back, keeping the neutral palm position throughout, then lower them under control to a full stretch. Squeeze your shoulder blades together at the top of the movement before lowering. Keep your core braced and your knees softly bent to support your lower back in the bent-over position. Avoid letting the elbows flare out to the sides, since the neutral grip is meant to keep them tracking close to your torso for better lat engagement.', videoId: 'KIdzT7ZJT0o' },
  bent_arm_pullover: { name: 'Bent-arm Pullover', muscle: 'Back', compound: true, restBase: 120, pattern: 'pullover', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Lie with your upper back flat on a bench, or positioned perpendicular across it, with your feet planted on the floor, holding a single dumbbell with both hands above your chest and your elbows bent at roughly 90 degrees. Lower the dumbbell in an arc behind your head until you feel a deep stretch across your chest and lats, keeping your elbow bend fixed throughout. Pull the dumbbell back over your chest to the starting position by contracting your lats and chest rather than your arms. Keep your hips slightly dropped below the bench line to increase the range of motion and stretch. Avoid straightening your arms during the movement, which turns it into a triceps-dominated skull crusher instead of a pullover targeting the chest and lats.', videoId: '4B-BrBH17uM' },
  close_grip_front_lat_pulldown: { name: 'Close-grip Front Lat Pulldown', muscle: 'Back', compound: true, restBase: 90, pattern: 'pulldown', equip: [{ v: 'cable', label: 'Cable' }], repLo: 8, repHi: 10, cue: 'Sit at the lat pulldown station with your thighs secured under the pad and grip the bar with hands close together, palms facing away from you or on a close neutral-grip attachment. Pull the bar down in front of you toward your upper chest by driving your elbows down and back, keeping your torso upright with only a slight backward lean. Pause briefly and squeeze your shoulder blades together before letting the bar rise under control back to a full stretch. Keep your chest up throughout rather than rounding forward to muscle the weight down. Avoid leaning back excessively or using body momentum to pull the bar down, since that shifts work away from the lats and onto the lower back.', videoId: 'ecRF8ERf2q4' },
  squat: { name: 'Squat', muscle: 'Quads', compound: true, restBase: 120, pattern: 'squat', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }, { v: 'machine', label: 'Machine' }, { v: 'bodyweight', label: 'Bodyweight' }], repLo: 6, repHi: 8, cue: 'Set a barbell across your upper back, feet roughly shoulder-width apart with toes turned slightly out, and brace your core before unracking the weight. Push your hips back and bend your knees to lower into the squat, keeping your chest up and your knees tracking in line with your toes until your hips drop to at least parallel with the floor. Drive through your whole foot to stand back up, keeping the bar path vertical over the middle of your foot. Keep your lower back in a neutral position throughout rather than rounding or excessively arching. A common mistake is letting the knees cave inward or rising with your hips shooting up first, which shifts stress onto the knees and lower back.', videoId: 'f-KL4VNN96E' },
  pistol_squat: { name: 'Pistol Squat', muscle: 'Quads', compound: true, restBase: 90, pattern: 'squat', equip: [{ v: 'machine', label: 'Machine' }, { v: 'kettlebell', label: 'Kettlebell' }], repLo: 8, repHi: 10, cue: 'Stand on one leg with your other leg extended straight out in front of you and your arms reaching forward for counterbalance. Bend the knee of your standing leg and push your hips back to lower into a squat, keeping your extended leg off the floor and your chest up as you descend as deep as your mobility allows. Keep your standing foot flat on the ground throughout, resisting the urge to rise onto your toes or let your heel lift. Drive through your standing heel to return to the starting position, keeping your knee tracking over your toes. Avoid letting your knee collapse inward or rounding your lower back to reach depth, since both are signs you should regress to an assisted or partial-range version first.', videoId: 'Ei1nwSCQx-0' },
  squat_to_a_bench: { name: 'Squat To A Bench', muscle: 'Quads', compound: true, restBase: 120, pattern: 'squat', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }], repLo: 6, repHi: 8, cue: 'Stand in front of a bench or box with feet shoulder-width apart, holding a barbell across your upper back or a dumbbell at your chest, and position yourself so the bench sits just behind you. Push your hips back and bend your knees to lower down with control until you lightly touch the bench with your hips, keeping your chest up and shins as vertical as possible. Avoid relaxing your full weight onto the bench; instead, tap it and immediately drive back up through your heels to standing. Keep tension in your legs throughout the touch-and-go motion rather than sitting and pausing. A common mistake is slamming down onto the bench or using it to bounce back up, which reduces control and can strain the lower back.', videoId: '6rpfubNjoqU' },
  box_squat_with_chains: { name: 'Box Squat With Chains', muscle: 'Quads', compound: true, restBase: 120, pattern: 'squat', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Set up a box or bench behind you at a height that lets your hips drop to at or slightly below parallel, and hang a set of chains from each end of a loaded barbell before unracking it onto your upper back. Push your hips back and bend your knees to sit back onto the box, keeping your shins close to vertical and your core braced, allowing the chains to deload as more links stack on the floor. Pause briefly on the box without relaxing your hips or losing tension, then drive explosively back up to standing as the chains lift off the floor and add resistance through the top of the range. Keep your weight balanced over your midfoot rather than shifting onto your toes as you descend. Avoid collapsing or bouncing off the box, since the pause is meant to remove momentum and force you to generate power from a dead stop.', videoId: 'PgyMb995DYc' },
  chair_squat: { name: 'Chair Squat', muscle: 'Quads', compound: true, restBase: 90, pattern: 'squat', equip: [{ v: 'machine', label: 'Machine' }], repLo: 8, repHi: 10, cue: 'Stand with your feet shoulder-width apart directly in front of a sturdy chair, arms extended forward or crossed at your chest for balance. Push your hips back and bend your knees to lower yourself under control until your glutes lightly tap the seat, keeping your chest up and knees tracking over your toes. Drive through your heels to stand back up to full hip extension, squeezing your glutes at the top. Keep the descent slow and controlled rather than dropping onto the chair, and avoid letting your knees cave inward as you rise.', videoId: 'GIz1C3yfE1s' },
  elevated_back_lunge: { name: 'Elevated Back Lunge', muscle: 'Quads', compound: true, restBase: 120, pattern: 'lunge', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Stand a couple of feet in front of a bench or step with your feet hip-width apart, holding dumbbells at your sides if using added resistance. Step one foot backward and place the top of that foot on the elevated surface, then lower your back knee toward the floor while bending the front knee to roughly 90 degrees. Keep your torso upright and most of your weight on the front heel as you drive back up to the starting position. Avoid letting the front knee collapse inward or shoot past your toes, and control the descent rather than dropping quickly onto the back leg.', videoId: 'exaNoccgvNs' },
  freehand_jump_squat: { name: 'Freehand Jump Squat', muscle: 'Quads', compound: true, restBase: 90, pattern: 'squat', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 8, repHi: 10, cue: 'Stand with your feet shoulder-width apart and your arms relaxed at your sides. Lower into a quarter-to-half squat by pushing your hips back and bending your knees, then explosively extend through your hips, knees, and ankles to jump straight up, swinging your arms upward for momentum. Land softly on the balls of your feet and roll down through the heel, immediately absorbing the impact by bending back into the squat position. Keep your chest up and knees aligned over your toes throughout, and avoid landing with stiff, locked knees, which puts excess stress on the joints.', videoId: 'tZSYZdtbONc' },
  front_squat_clean_grip: { name: 'Front Squat (clean Grip)', muscle: 'Quads', compound: true, restBase: 120, pattern: 'squat', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Set the bar in a squat rack at roughly chest height and grip it just outside shoulder width, rotating your elbows up and forward so the bar rests on your front deltoids and is cradled by your fingertips in the clean grip position. Unrack the bar, step back, and stand with feet shoulder-width apart before initiating the squat by pushing your hips back and bending your knees while keeping your torso as upright as possible. Descend until your hips drop below parallel, then drive through your midfoot to stand back up, keeping your elbows high throughout. The key cue is to keep your elbows up and chest tall; letting your elbows drop causes the bar to roll forward and forces you to round your back.', videoId: 'tW2H0Ib_hQw' },
  front_squat_to_a_bench: { name: 'Front Squat To A Bench', muscle: 'Quads', compound: true, restBase: 120, pattern: 'squat', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 6, repHi: 8, cue: 'Position a bench or box behind you at a height that limits your squat to the desired depth, then set up in the front squat position with the bar racked across your front deltoids, elbows high and grip just outside shoulder width. Push your hips back and bend your knees to lower under control until your glutes lightly touch the bench, keeping your chest up and heels planted. Without relaxing or sitting fully down, immediately reverse the movement by driving through your midfoot back to standing. Use the bench only as a depth guide and touchpoint, not a resting surface, and avoid letting your knees drift inward as you stand up.', videoId: 'v-mQm_droHg' },
  calf_press: { name: 'Calf Press', muscle: 'Calves', compound: false, restBase: 60, pattern: 'leg_press', equip: [{ v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Sit in the leg press machine with your feet placed on the lower portion of the platform, only the balls of your feet and toes in contact, and extend your legs to roughly three-quarters of full extension before releasing the safety catches. Keeping your knees slightly bent and locked in that position, point your toes away from you to press the platform outward, then flex your ankles to let your heels drop back below the platform edge for a full stretch. Focus on driving the movement entirely from your ankles rather than your knees. Avoid fully locking out your knees during the set, since that shifts load away from the calves and onto the joint.', videoId: 'J2TH-qxq2d4' },
  calf_raise_machine: { name: 'Calf Raise', muscle: 'Calves', compound: false, restBase: 60, pattern: 'calf_raise', equip: [{ v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Step into the standing calf raise machine and position your shoulders under the pads with the balls of your feet on the platform edge and your heels hanging off. Stand tall with a slight bend in your knees and lower your heels below the platform to feel a deep stretch in your calves. Press through the balls of your feet to rise as high onto your toes as possible, pausing briefly at the top to squeeze your calves. Keep your knees in a fixed, slightly bent position throughout and avoid bouncing at the bottom, which reduces tension and increases strain on the Achilles tendon.', videoId: 'SorIB5_zO9A' },
  reverse_calf_raises: { name: 'Reverse Calf Raises', muscle: 'Calves', compound: false, restBase: 60, pattern: 'calf_raise', equip: [{ v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Stand tall with your heels on the edge of a step or plate and your toes hanging off, or stand flat on the floor if unweighted, holding onto something stable for balance. Keeping your legs straight, lift your toes and the front of your feet as high as possible by flexing at the ankle, then lower them back down under control until you feel a stretch in your shins. Move slowly through a full range of motion rather than using momentum. This exercise directly targets the tibialis anterior, so avoid rushing the reps or letting your knees bend to compensate, which takes tension off the target muscle.', videoId: 'Jczf0pJ1lmE' },
  rocking_standing_calf_raise: { name: 'Rocking Standing Calf Raise', muscle: 'Calves', compound: false, restBase: 60, pattern: 'calf_raise', equip: [{ v: 'barbell', label: 'Barbell' }], repLo: 10, repHi: 12, cue: 'Stand holding a barbell across your upper back or dumbbells at your sides, feet hip-width apart on a flat surface or the edge of a platform. Rock forward onto the balls of your feet and press up as high as possible onto your toes, then rock backward to lift your toes and shift weight toward your heels, moving continuously between the two positions. Keep your core braced and knees soft throughout to protect your lower back from the shifting weight. Avoid using large, jerky rocking movements; the transitions should be controlled so the calves and shins do the work rather than momentum.', videoId: '-IKfUV5y6Jc' },
  seated_one_leg_calf_raise: { name: 'Seated One-leg Calf Raise', muscle: 'Calves', compound: false, restBase: 60, pattern: 'calf_raise', equip: [{ v: 'dumbbell', label: 'Dumbbell' }], repLo: 10, repHi: 12, cue: 'Sit at a seated calf raise machine or on a bench with a dumbbell resting on one knee, placing the ball of that foot on the platform or a raised block with your heel hanging off. Lower the thigh pad or keep the dumbbell steady, then lower your heel as far as comfortable to stretch the calf before pressing through the ball of your foot to raise it as high as possible. Perform the full set on one leg before switching sides, focusing on a slow, controlled tempo. Avoid shifting the weight onto the other leg or using momentum to bounce out of the bottom position.', videoId: 'Ih4bGiKq4Ac' },
  glute_kickback: { name: 'Glute Kickback', muscle: 'Glutes', compound: true, restBase: 90, pattern: 'glute_kickback', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 8, repHi: 10, cue: 'Attach an ankle cuff to a low cable pulley and secure it around one ankle, then face the machine and hold onto the frame or handles for support with a slight forward lean and a soft bend in your standing knee. Keeping a slight bend in the working knee, extend your leg backward and up by squeezing your glute, driving the movement from the hip rather than the lower back. Pause briefly at the top before returning under control to the starting position without letting the cable stack touch down. Avoid arching or rotating your lower back to gain extra range of motion; the movement should come purely from hip extension.', videoId: '5jJNfIlKTmg' },
  one_legged_kickback: { name: 'One-legged Kickback', muscle: 'Glutes', compound: false, restBase: 60, pattern: 'glute_kickback', equip: [{ v: 'cable', label: 'Cable' }], repLo: 10, repHi: 12, cue: 'Get into a tabletop position on your hands and knees with your wrists under your shoulders and knees under your hips, keeping your core braced and spine neutral. Keeping your knee bent at roughly 90 degrees, lift one leg up and back by driving your heel toward the ceiling until your thigh is in line with your torso, squeezing your glute at the top. Lower the knee back down under control without letting it touch the floor between reps, and complete all reps on one side before switching. Avoid arching your lower back or rotating your hips to gain extra height; the motion should stay isolated to the hip.', videoId: 'OV8FGnvsOOE' },
  single_leg_glute_bridge: { name: 'Single Leg Glute Bridge', muscle: 'Glutes', compound: false, restBase: 60, pattern: 'hip_thrust', equip: [{ v: 'bodyweight', label: 'Bodyweight' }], repLo: 10, repHi: 12, cue: 'Lie on your back with your knees bent and feet flat on the floor, then extend one leg straight out so only your heel or foot remains lightly hovering, keeping both knees in line. Press through the heel of your grounded foot and squeeze your glutes to lift your hips off the floor until your body forms a straight line from shoulders to knee, holding briefly at the top. Lower back down under control without letting your hips sag or rotate to one side. Keep your hips level throughout the movement; the most common mistake is letting the hip on the lifted-leg side drop, which shifts the work away from the glute and strains the lower back.', videoId: '_K_di6h2-Wg' },
  stiff_legged_deadlift: { name: 'Stiff-legged Deadlift', muscle: 'Hamstrings', compound: true, restBase: 120, pattern: 'hinge', equip: [{ v: 'barbell', label: 'Barbell' }, { v: 'dumbbell', label: 'Dumbbell' }, { v: 'machine', label: 'Machine' }], repLo: 6, repHi: 8, cue: 'Stand with feet hip-width apart, a barbell in front of your shins, and grip it just outside your legs with your knees only slightly bent throughout the movement. Hinge forward at the hips, keeping the bar close to your legs and your spine neutral, and lower it toward mid-shin while pushing your hips back until you feel a strong stretch in your hamstrings. Reverse the motion by driving your hips forward and squeezing your glutes to return to standing, keeping the bar path close to your body the entire time. Avoid rounding your lower back or bending your knees significantly to chase depth; range of motion should be limited by hamstring flexibility, not by sacrificing spinal position.', videoId: 'q3mVYFBaLq4' },
  lunge_pass_through: { name: 'Lunge Pass Through', muscle: 'Hamstrings', compound: true, restBase: 120, pattern: 'lunge', equip: [{ v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Stand holding a kettlebell in both hands at chest height with your feet shoulder-width apart. Step forward into a lunge with one leg, bending both knees toward 90 degrees while keeping your torso upright, and as you lunge, pass the kettlebell around and under your front knee, transferring it from hand to hand. Push through your front heel to return to standing, bringing the kettlebell back to chest height, and alternate legs each rep. Keep your core braced and movements controlled during the hand-off under the knee, and avoid letting your front knee cave inward or your back round as you reach down.', videoId: 'Vfx9-YwMkQ4' },
  one_legged_deadlift: { name: 'One-legged Deadlift', muscle: 'Hamstrings', compound: true, restBase: 120, pattern: 'hinge', equip: [{ v: 'kettlebell', label: 'Kettlebell' }], repLo: 6, repHi: 8, cue: 'Stand on one leg holding a dumbbell in the opposite hand, with a soft bend in your standing knee. Hinge forward at the hips while simultaneously extending your free leg straight back behind you, lowering the dumbbell toward the floor until your torso and back leg are roughly parallel to the ground, keeping your hips square. Squeeze your glute and hamstring on the standing leg to pull yourself back up to a tall standing position, tapping your back foot down briefly between reps if needed for balance. Keep your spine neutral and shoulders level throughout, and avoid letting your hips rotate open, which is the most common technique breakdown on this movement.', videoId: 'Zfr6wizR8rs' },
  lying_leg_curls: { name: 'Lying Leg Curls', muscle: 'Hamstrings', compound: false, restBase: 60, pattern: 'leg_curl', equip: [{ v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Lie face down on the leg curl machine with the padded lever resting just above your heels and your knees aligned with the machine\'s pivot point, gripping the handles or the bench edge for stability. Curl your heels up toward your glutes by flexing your knees, squeezing your hamstrings hard at the top of the movement without lifting your hips off the pad. Lower the weight back down under control to full leg extension without letting the weight stack slam. Keep your hips pressed into the bench throughout; arching your back or lifting your hips to move more weight takes tension off the hamstrings.', videoId: 'lUH80pneL5w' },
  standing_leg_curl: { name: 'Standing Leg Curl', muscle: 'Hamstrings', compound: false, restBase: 60, pattern: 'leg_curl', equip: [{ v: 'machine', label: 'Machine' }], repLo: 10, repHi: 12, cue: 'Stand at the standing leg curl machine with the pad positioned just above the back of your ankle on the working leg and your hips pressed against the support pad, holding the handles for balance. Keeping your standing leg stable and your hips square to the machine, curl the pad up toward your glutes by flexing your knee, squeezing your hamstring at the top of the movement. Lower back down under control to full extension without letting the weight stack bounce. Avoid leaning forward or letting your hips shift back to generate momentum, which reduces isolation of the hamstring.', videoId: 'rDRwAURNbzU' }
};

